// wallet.js - Enhanced Wallet System (Global + Per-Game Sub-Wallets)


/**
 * Get or create global wallet for user
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {string} userId - User ID
 * @returns {object} Global wallet data
 */
function getGlobalWallet(nk, logger, userId) {
    var collection = "wallets";
    var key = makeGlobalStorageKey("global_wallet", userId);

    var wallet = readStorage(nk, logger, collection, key, userId);

    if (!wallet) {
        // Initialize new global wallet with BOTH key formats
        wallet = {
            userId: userId,
            currencies: {
                global: 0,  // Unity client key
                xut: 0,     // Legacy/XUT token key
                xp: 0
            },
            items: {},
            nfts: [],
            createdAt: getCurrentTimestamp()
        };
    }

    // Ensure both keys exist (migration for existing wallets)
    if (wallet.currencies) {
        if (wallet.currencies.global === undefined) {
            wallet.currencies.global = wallet.currencies.xut || 0;
        }
        if (wallet.currencies.xut === undefined) {
            wallet.currencies.xut = wallet.currencies.global || 0;
        }
    }

    return wallet;
}

/**
 * Get or create game-specific wallet for user
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {string} userId - User ID
 * @param {string} gameId - Game ID (UUID)
 * @returns {object} Game wallet data
 */
function getGameWallet(nk, logger, userId, gameId) {
    var collection = "wallets";
    var key = makeGameStorageKey("wallet", userId, gameId);

    var wallet = readStorage(nk, logger, collection, key, userId);

    if (!wallet) {
        // Initialize new game wallet with BOTH key formats
        wallet = {
            userId: userId,
            gameId: gameId,
            currencies: {
                game: 0,    // Unity client key
                tokens: 0,  // Legacy key
                xp: 0
            },
            items: {},
            consumables: {},
            cosmetics: {},
            createdAt: getCurrentTimestamp()
        };
    }

    // Ensure both keys exist (migration for existing wallets)
    if (wallet.currencies) {
        if (wallet.currencies.game === undefined) {
            wallet.currencies.game = wallet.currencies.tokens || 0;
        }
        if (wallet.currencies.tokens === undefined) {
            wallet.currencies.tokens = wallet.currencies.game || 0;
        }
    }

    return wallet;
}

/**
 * Save global wallet
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {string} userId - User ID
 * @param {object} wallet - Wallet data
 * @returns {boolean} Success status
 */
function saveGlobalWallet(nk, logger, userId, wallet) {
    var collection = "wallets";
    var key = makeGlobalStorageKey("global_wallet", userId);
    wallet.updatedAt = getCurrentTimestamp();
    return writeStorage(nk, logger, collection, key, userId, wallet);
}

/**
 * Save game wallet
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {string} userId - User ID
 * @param {string} gameId - Game ID (UUID)
 * @param {object} wallet - Wallet data
 * @returns {boolean} Success status
 */
function saveGameWallet(nk, logger, userId, gameId, wallet) {
    var collection = "wallets";
    var key = makeGameStorageKey("wallet", userId, gameId);
    wallet.updatedAt = getCurrentTimestamp();
    return writeStorage(nk, logger, collection, key, userId, wallet);
}

/**
 * Log transaction
 * PR #6: Added log sanitization for sensitive data
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {string} userId - User ID
 * @param {object} transaction - Transaction data
 */
function logTransaction(nk, logger, userId, transaction) {
    var key = "transaction_log_" + userId + "_" + getUnixTimestamp();
    transaction.timestamp = getCurrentTimestamp();
    transaction.userId = userId;
    
    // Store full transaction for audit
    writeStorage(nk, logger, "transaction_logs", key, userId, transaction);
    
    // PR #6: Log sanitized version to console (mask sensitive values)
    try {
        var logSafe = {
            type: transaction.type,
            userId: userId ? userId.substring(0, 8) + '...' : 'unknown',
            currency: transaction.currency,
            operation: transaction.operation,
            timestamp: transaction.timestamp
        };
        // Don't log actual amounts to console
        if (typeof globalThis !== 'undefined' && globalThis.Security) {
            logSafe = globalThis.Security.sanitizeForLogging(transaction);
        }
        logInfo(logger, '[Transaction] ' + transaction.type + ' for user ' + (userId ? userId.substring(0, 8) + '...' : 'unknown'));
    } catch (e) {
        // Silent fail for logging
    }
}

/**
 * RPC: Get all wallets (global + all game wallets)
 * @param {object} ctx - Request context
 * @param {object} logger - Logger instance
 * @param {object} nk - Nakama runtime
 * @param {string} payload - JSON payload (empty)
 * @returns {string} JSON response
 */
function rpcWalletGetAll(ctx, logger, nk, payload) {
    logInfo(logger, "RPC wallet_get_all called");

    var userId = ctx.userId;
    if (!userId) {
        return handleError(ctx, null, "User not authenticated");
    }

    // Get global wallet
    var globalWallet = getGlobalWallet(nk, logger, userId);

    // Get all game wallets
    var gameWallets = [];
    try {
        var records = nk.storageList(userId, "wallets", 100);
        for (var i = 0; i < records.length; i++) {
            if (records[i].key.indexOf("wallet_" + userId + "_") === 0) {
                gameWallets.push(records[i].value);
            }
        }
    } catch (err) {
        logWarn(logger, "Failed to list game wallets: " + err.message);
    }

    return JSON.stringify({
        success: true,
        userId: userId,
        globalWallet: globalWallet,
        gameWallets: gameWallets,
        timestamp: getCurrentTimestamp()
    });
}

/**
 * RPC: Update global wallet
 * PR #6: Added secure amount validation and atomic operations
 * @param {object} ctx - Request context
 * @param {object} logger - Logger instance
 * @param {object} nk - Nakama runtime
 * @param {string} payload - JSON payload with { currency: "xut", amount: 100, operation: "add" }
 * @returns {string} JSON response
 */
function rpcWalletUpdateGlobal(ctx, logger, nk, payload) {
    logInfo(logger, "RPC wallet_update_global called");

    var parsed = safeJsonParse(payload);
    if (!parsed.success) {
        return handleError(ctx, null, "Invalid JSON payload");
    }

    var data = parsed.data;
    var validation = validatePayload(data, ['currency', 'amount', 'operation']);
    if (!validation.valid) {
        return handleError(ctx, null, "Missing required fields: " + validation.missing.join(", "));
    }

    var userId = ctx.userId;
    if (!userId) {
        return handleError(ctx, null, "User not authenticated");
    }

    var currency = data.currency;
    var operation = data.operation; // "add" or "subtract"

    // Validate operation
    if (operation !== "add" && operation !== "subtract") {
        return handleError(ctx, null, "Invalid operation: " + operation + ". Must be 'add' or 'subtract'");
    }

    // PR #6: CRITICAL - Validate and sanitize amount (reject negative)
    var amountValidation;
    if (
        typeof globalThis !== 'undefined' &&
        globalThis.Security &&
        typeof globalThis.Security.validateWalletAmount === 'function'
    ) {
        try {
            amountValidation = globalThis.Security.validateWalletAmount(data.amount, operation);
            if (!amountValidation || !amountValidation.valid) {
                return JSON.stringify({
                    success: false,
                    error: (amountValidation && amountValidation.error) ? amountValidation.error : 'Invalid wallet amount',
                    errorCode: 'INVALID_AMOUNT'
                });
            }
        } catch (validationErr) {
            logger.warn('[Wallet] wallet_update_global validateWalletAmount failed, using fallback validation: ' + validationErr.message);
            amountValidation = null;
        }
    }

    if (!amountValidation) {
        // Fallback validation
        var amount = Math.abs(Number(data.amount));
        if (isNaN(amount) || amount <= 0) {
            return handleError(ctx, null, "Amount must be a positive number");
        }
        amountValidation = { sanitizedAmount: Math.floor(amount) };
    }

    var amount = amountValidation.sanitizedAmount;
    var reason = data.reason || 'wallet_update';

    // PR #6: Use secure wallet update with version checking
    if (
        typeof globalThis !== 'undefined' &&
        globalThis.Security &&
        typeof globalThis.Security.secureWalletUpdate === 'function'
    ) {
        try {
            var result = globalThis.Security.secureWalletUpdate(
                nk, logger, userId, null, // null gameId = global wallet
                currency, amount, operation, reason
            );

            if (!result || !result.success) {
                var secureError = (result && result.error) ? String(result.error) : 'Global wallet update failed';
                return JSON.stringify({
                    success: false,
                    error: secureError,
                    errorCode: secureError.indexOf('Insufficient') !== -1 ? 'INSUFFICIENT_BALANCE' : 'WALLET_ERROR'
                });
            }

            return JSON.stringify({
                success: true,
                userId: userId,
                currency: currency,
                oldBalance: result.oldBalance,
                newBalance: result.newBalance,
                transactionId: result.transactionId,
                timestamp: getCurrentTimestamp()
            });
        } catch (secureErr) {
            logger.warn('[Wallet] wallet_update_global secureWalletUpdate failed, falling back: ' + secureErr.message);
        }
    }

    // Fallback to original logic (with amount now validated)
    var wallet = getGlobalWallet(nk, logger, userId);

    if (!wallet.currencies[currency]) {
        wallet.currencies[currency] = 0;
    }

    var oldBalance = wallet.currencies[currency];

    if (operation === "add") {
        wallet.currencies[currency] += amount;
    } else if (operation === "subtract") {
        if (wallet.currencies[currency] < amount) {
            return JSON.stringify({
                success: false,
                error: "Insufficient balance. Available: " + wallet.currencies[currency] + ", Required: " + amount,
                errorCode: 'INSUFFICIENT_BALANCE'
            });
        }
        wallet.currencies[currency] -= amount;
    }

    // Sync duplicate keys
    if (currency === 'global' || currency === 'xut') {
        wallet.currencies.global = wallet.currencies[currency];
        wallet.currencies.xut = wallet.currencies[currency];
    }

    if (!saveGlobalWallet(nk, logger, userId, wallet)) {
        return handleError(ctx, null, "Failed to save global wallet");
    }

    logTransaction(nk, logger, userId, {
        type: "global_wallet_update",
        currency: currency,
        amount: amount,
        operation: operation,
        oldBalance: oldBalance,
        newBalance: wallet.currencies[currency]
    });

    return JSON.stringify({
        success: true,
        userId: userId,
        currency: currency,
        oldBalance: oldBalance,
        newBalance: wallet.currencies[currency],
        timestamp: getCurrentTimestamp()
    });
}

/**
 * RPC: Update game wallet
 * PR #6: Added secure amount validation and atomic operations
 * @param {object} ctx - Request context
 * @param {object} logger - Logger instance
 * @param {object} nk - Nakama runtime
 * @param {string} payload - JSON payload with { gameId: "uuid", currency: "tokens", amount: 100, operation: "add" }
 * @returns {string} JSON response
 */
function rpcWalletUpdateGameWallet(ctx, logger, nk, payload) {
    logInfo(logger, "RPC wallet_update_game_wallet called");

    var parsed = safeJsonParse(payload);
    if (!parsed.success) {
        return handleError(ctx, null, "Invalid JSON payload");
    }

    var data = parsed.data;
    var validation = validatePayload(data, ['gameId', 'currency', 'amount', 'operation']);
    if (!validation.valid) {
        return handleError(ctx, null, "Missing required fields: " + validation.missing.join(", "));
    }

    var gameId = data.gameId;
    if (!isValidUUID(gameId)) {
        return handleError(ctx, null, "Invalid gameId UUID format");
    }

    var userId = ctx.userId;
    if (!userId) {
        return handleError(ctx, null, "User not authenticated");
    }

    var currency = data.currency;
    var operation = data.operation;

    // Validate operation
    if (operation !== "add" && operation !== "subtract") {
        return handleError(ctx, null, "Invalid operation: " + operation + ". Must be 'add' or 'subtract'");
    }

    // PR #6: CRITICAL - Validate and sanitize amount (reject negative)
    var amountValidation;
    if (
        typeof globalThis !== 'undefined' &&
        globalThis.Security &&
        typeof globalThis.Security.validateWalletAmount === 'function'
    ) {
        try {
            amountValidation = globalThis.Security.validateWalletAmount(data.amount, operation);
            if (!amountValidation || !amountValidation.valid) {
                return JSON.stringify({
                    success: false,
                    error: (amountValidation && amountValidation.error) ? amountValidation.error : 'Invalid wallet amount',
                    errorCode: 'INVALID_AMOUNT'
                });
            }
        } catch (validationErr) {
            logger.warn('[Wallet] wallet_update_game_wallet validateWalletAmount failed, using fallback validation: ' + validationErr.message);
            amountValidation = null;
        }
    }

    if (!amountValidation) {
        // Fallback validation
        var rawAmount = Math.abs(Number(data.amount));
        if (isNaN(rawAmount) || rawAmount <= 0) {
            return handleError(ctx, null, "Amount must be a positive number");
        }
        amountValidation = { sanitizedAmount: Math.floor(rawAmount) };
    }

    var amount = amountValidation.sanitizedAmount;
    var reason = data.reason || 'game_wallet_update';

    // PR #6: Use secure wallet update with version checking
    if (
        typeof globalThis !== 'undefined' &&
        globalThis.Security &&
        typeof globalThis.Security.secureWalletUpdate === 'function'
    ) {
        try {
            var result = globalThis.Security.secureWalletUpdate(
                nk, logger, userId, gameId,
                currency, amount, operation, reason
            );

            if (!result || !result.success) {
                var secureError = (result && result.error) ? String(result.error) : 'Wallet update failed';
                return JSON.stringify({
                    success: false,
                    error: secureError,
                    errorCode: secureError.indexOf('Insufficient') !== -1 ? 'INSUFFICIENT_BALANCE' : 'WALLET_ERROR'
                });
            }

            return JSON.stringify({
                success: true,
                userId: userId,
                gameId: gameId,
                currency: currency,
                oldBalance: result.oldBalance,
                newBalance: result.newBalance,
                transactionId: result.transactionId,
                game_balance: result.wallet.currencies.game || 0,
                currencies: result.wallet.currencies,
                timestamp: getCurrentTimestamp()
            });
        } catch (secureErr) {
            logger.warn('[Wallet] wallet_update_game_wallet secureWalletUpdate failed, falling back: ' + secureErr.message);
        }
    }

    // Fallback to original logic (with amount now validated)
    var wallet = getGameWallet(nk, logger, userId, gameId);

    // NORMALIZE: Map client currency keys to storage keys
    var currenciesToUpdate = [];
    if (currency === "game" || currency === "tokens") {
        currenciesToUpdate = ["game", "tokens"];
    } else {
        currenciesToUpdate = [currency];
    }

    // Initialize currencies if not exists
    for (var i = 0; i < currenciesToUpdate.length; i++) {
        var curr = currenciesToUpdate[i];
        if (wallet.currencies[curr] === undefined || wallet.currencies[curr] === null) {
            wallet.currencies[curr] = 0;
        }
    }

    // Check balance before subtract
    if (operation === "subtract") {
        var currentBalance = wallet.currencies[currenciesToUpdate[0]] || 0;
        if (currentBalance < amount) {
            return JSON.stringify({
                success: false,
                error: "Insufficient balance. Available: " + currentBalance + ", Required: " + amount,
                errorCode: 'INSUFFICIENT_BALANCE'
            });
        }
    }

    var oldBalance = wallet.currencies[currenciesToUpdate[0]] || 0;

    // Update all mapped currencies
    for (var i = 0; i < currenciesToUpdate.length; i++) {
        var curr = currenciesToUpdate[i];
        if (operation === "add") {
            wallet.currencies[curr] += amount;
        } else if (operation === "subtract") {
            wallet.currencies[curr] -= amount;
        }
    }

    if (!saveGameWallet(nk, logger, userId, gameId, wallet)) {
        return handleError(ctx, null, "Failed to save game wallet");
    }

    logTransaction(nk, logger, userId, {
        type: "game_wallet_update",
        gameId: gameId,
        currency: currency,
        amount: amount,
        operation: operation,
        oldBalance: oldBalance,
        newBalance: wallet.currencies[currency] || wallet.currencies.game || 0
    });

    logInfo(logger, "Wallet updated successfully.  New balances - game: " +
        wallet.currencies.game + ", tokens: " + wallet.currencies.tokens);

    return JSON.stringify({
        success: true,
        userId: userId,
        gameId: gameId,
        currency: currency,
        oldBalance: oldBalance,
        newBalance: wallet.currencies[currency] || wallet.currencies.game || 0,
        game_balance: wallet.currencies.game || 0,
        global_balance: wallet.currencies.global || wallet.currencies.xut || 0,
        currencies: wallet.currencies,
        timestamp: getCurrentTimestamp()
    });
}

/**
 * RPC: Transfer between game wallets
 * PR #6: CRITICAL FIX - Now uses atomic transfer with rollback protection
 * @param {object} ctx - Request context
 * @param {object} logger - Logger instance
 * @param {object} nk - Nakama runtime
 * @param {string} payload - JSON with { fromGameId: "uuid", toGameId: "uuid", currency: "tokens", amount: 100 }
 * @returns {string} JSON response
 */
function rpcWalletTransferBetweenGameWallets(ctx, logger, nk, payload) {
    logInfo(logger, "RPC wallet_transfer_between_game_wallets called");

    var parsed = safeJsonParse(payload);
    if (!parsed.success) {
        return handleError(ctx, null, "Invalid JSON payload");
    }

    var data = parsed.data;
    var validation = validatePayload(data, ['fromGameId', 'toGameId', 'currency', 'amount']);
    if (!validation.valid) {
        return handleError(ctx, null, "Missing required fields: " + validation.missing.join(", "));
    }

    var fromGameId = data.fromGameId;
    var toGameId = data.toGameId;

    if (!isValidUUID(fromGameId) || !isValidUUID(toGameId)) {
        return handleError(ctx, null, "Invalid gameId UUID format");
    }

    if (fromGameId === toGameId) {
        return JSON.stringify({
            success: false,
            error: "Cannot transfer to the same wallet",
            errorCode: 'INVALID_TRANSFER'
        });
    }

    var userId = ctx.userId;
    if (!userId) {
        return handleError(ctx, null, "User not authenticated");
    }

    var currency = data.currency;

    // PR #6: CRITICAL - Validate and sanitize amount (reject negative)
    var amountValidation;
    if (typeof globalThis !== 'undefined' && globalThis.Security) {
        amountValidation = globalThis.Security.validateWalletAmount(data.amount, 'transfer');
        if (!amountValidation.valid) {
            return JSON.stringify({
                success: false,
                error: amountValidation.error,
                errorCode: 'INVALID_AMOUNT'
            });
        }
    } else {
        var rawAmount = Math.abs(Number(data.amount));
        if (isNaN(rawAmount) || rawAmount <= 0) {
            return JSON.stringify({
                success: false,
                error: "Amount must be a positive number",
                errorCode: 'INVALID_AMOUNT'
            });
        }
        amountValidation = { sanitizedAmount: Math.floor(rawAmount) };
    }

    var amount = amountValidation.sanitizedAmount;

    // PR #6: Use atomic transfer with rollback protection
    if (typeof globalThis !== 'undefined' && globalThis.Security) {
        var result = globalThis.Security.atomicWalletTransfer(
            nk, logger, userId, fromGameId, toGameId, currency, amount
        );

        if (!result.success) {
            var errorCode = 'TRANSFER_FAILED';
            if (result.error.indexOf('Insufficient') !== -1) errorCode = 'INSUFFICIENT_BALANCE';
            if (result.error.indexOf('conflict') !== -1) errorCode = 'VERSION_CONFLICT';
            if (result.error.indexOf('not found') !== -1) errorCode = 'WALLET_NOT_FOUND';

            return JSON.stringify({
                success: false,
                error: result.error,
                errorCode: errorCode
            });
        }

        return JSON.stringify({
            success: true,
            userId: userId,
            fromGameId: fromGameId,
            toGameId: toGameId,
            currency: currency,
            amount: amount,
            fromBalance: result.fromBalance,
            toBalance: result.toBalance,
            transactionId: result.transactionId,
            timestamp: getCurrentTimestamp()
        });
    }

    // Fallback: Original logic with improved validation (but still non-atomic)
    logWarn(logger, "[WalletTransfer] Security module not loaded - using fallback non-atomic transfer");

    var fromWallet = getGameWallet(nk, logger, userId, fromGameId);
    var toWallet = getGameWallet(nk, logger, userId, toGameId);

    var fromBalance = fromWallet.currencies[currency] || 0;
    if (fromBalance < amount) {
        return JSON.stringify({
            success: false,
            error: "Insufficient balance. Available: " + fromBalance + ", Required: " + amount,
            errorCode: 'INSUFFICIENT_BALANCE'
        });
    }

    // Transfer
    fromWallet.currencies[currency] = fromBalance - amount;
    if (!toWallet.currencies[currency]) {
        toWallet.currencies[currency] = 0;
    }
    toWallet.currencies[currency] += amount;

    // Sync duplicate keys
    if (currency === 'game' || currency === 'tokens') {
        fromWallet.currencies.game = fromWallet.currencies[currency];
        fromWallet.currencies.tokens = fromWallet.currencies[currency];
        toWallet.currencies.game = toWallet.currencies[currency];
        toWallet.currencies.tokens = toWallet.currencies[currency];
    }

    // Save both wallets (WARNING: Non-atomic in fallback mode)
    if (!saveGameWallet(nk, logger, userId, fromGameId, fromWallet)) {
        return JSON.stringify({
            success: false,
            error: "Failed to save source wallet",
            errorCode: 'TRANSFER_FAILED'
        });
    }
    if (!saveGameWallet(nk, logger, userId, toGameId, toWallet)) {
        // Attempt rollback
        fromWallet.currencies[currency] = fromBalance;
        saveGameWallet(nk, logger, userId, fromGameId, fromWallet);
        return JSON.stringify({
            success: false,
            error: "Failed to save destination wallet - rollback attempted",
            errorCode: 'TRANSFER_FAILED'
        });
    }

    logTransaction(nk, logger, userId, {
        type: "wallet_transfer",
        fromGameId: fromGameId,
        toGameId: toGameId,
        currency: currency,
        amount: amount,
        fromBalanceBefore: fromBalance,
        fromBalanceAfter: fromWallet.currencies[currency],
        toBalanceAfter: toWallet.currencies[currency]
    });

    return JSON.stringify({
        success: true,
        userId: userId,
        fromGameId: fromGameId,
        toGameId: toGameId,
        currency: currency,
        amount: amount,
        fromBalance: fromWallet.currencies[currency],
        toBalance: toWallet.currencies[currency],
        timestamp: getCurrentTimestamp()
    });
}

