// ============================================================================
// PUSH_NOTIFICATIONS/PUSH_NOTIFICATIONS.JS
// ============================================================================

// push_notifications.js - Push Notification System (AWS SNS + Pinpoint + Lambda)
// Unity does NOT use AWS SDK - Unity only sends raw push tokens
// Nakama forwards to AWS Lambda Function URL for endpoint creation


/**
 * Lambda Function URL for push endpoint registration
 * Can be configured via environment variable: PUSH_LAMBDA_URL
 */
var LAMBDA_FUNCTION_URL = "https://your-lambda-url.lambda-url.region.on.aws/register-endpoint";

/**
 * Lambda Function URL for sending push notifications
 * Can be configured via environment variable: PUSH_SEND_URL
 */
var LAMBDA_PUSH_URL = "https://your-lambda-url.lambda-url.region.on.aws/send-push";

/**
 * Helper: Get configured Lambda URLs from environment
 */
function getPushConfig(ctx) {
    var config = {
        registerUrl: LAMBDA_FUNCTION_URL,
        sendUrl: LAMBDA_PUSH_URL,
        enabled: false
    };
    
    if (ctx && ctx.env) {
        if (ctx.env["PUSH_LAMBDA_URL"]) {
            config.registerUrl = ctx.env["PUSH_LAMBDA_URL"];
            config.enabled = true;
        }
        if (ctx.env["PUSH_SEND_URL"]) {
            config.sendUrl = ctx.env["PUSH_SEND_URL"];
            config.enabled = true;
        }
    }
    
    return config;
}

/**
 * Platform token types
 */
var PLATFORM_TYPES = {
    ios: "APNS",
    android: "FCM",
    web: "FCM",
    windows: "WNS"
};

/**
 * Store endpoint ARN for user device
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {string} userId - User ID
 * @param {string} gameId - Game ID (UUID)
 * @param {string} platform - Platform type (ios, android, web, windows)
 * @param {string} endpointArn - SNS endpoint ARN
 * @returns {boolean} Success status
 */
function storeEndpointArn(nk, logger, userId, gameId, platform, endpointArn) {
    var collection = "push_endpoints";
    var key = "push_endpoint_" + userId + "_" + gameId + "_" + platform;

    var data = {
        userId: userId,
        gameId: gameId,
        platform: platform,
        endpointArn: endpointArn,
        createdAt: getCurrentTimestamp(),
        updatedAt: getCurrentTimestamp()
    };

    return writeStorage(nk, logger, collection, key, userId, data);
}

/**
 * Get endpoint ARN for user device
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {string} userId - User ID
 * @param {string} gameId - Game ID (UUID)
 * @param {string} platform - Platform type
 * @returns {object|null} Endpoint data or null
 */
function getEndpointArn(nk, logger, userId, gameId, platform) {
    var collection = "push_endpoints";
    var key = "push_endpoint_" + userId + "_" + gameId + "_" + platform;
    return readStorage(nk, logger, collection, key, userId);
}

/**
 * Get all endpoint ARNs for user
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {string} userId - User ID
 * @param {string} gameId - Game ID (UUID)
 * @returns {Array} List of endpoint data
 */
function getAllEndpointArns(nk, logger, userId, gameId) {
    var collection = "push_endpoints";
    var endpoints = [];

    try {
        var records = nk.storageList(userId, collection, 100);
        for (var i = 0; i < records.length; i++) {
            var value = records[i].value;
            if (value.gameId === gameId) {
                endpoints.push(value);
            }
        }
    } catch (err) {
        logWarn(logger, "Failed to list endpoints: " + err.message);
    }

    return endpoints;
}

/**
 * RPC: Register device token
 * Unity sends raw device token, Nakama forwards to Lambda
 * Lambda creates SNS endpoint and returns ARN
 * 
 * @param {object} ctx - Request context
 * @param {object} logger - Logger instance
 * @param {object} nk - Nakama runtime
 * @param {string} payload - JSON payload with:
 *   {
 *     gameId: "uuid",
 *     platform: "ios"|"android"|"web"|"windows",
 *     token: "raw_device_token"
 *   }
 * @returns {string} JSON response
 */
function rpcPushRegisterToken(ctx, logger, nk, payload) {
    logInfo(logger, "RPC push_register_token called");

    var parsed = safeJsonParse(payload);
    if (!parsed.success) {
        return handleError(ctx, null, "Invalid JSON payload");
    }

    var data = parsed.data;
    var validation = validatePayload(data, ['gameId', 'platform', 'token']);
    if (!validation.valid) {
        return handleError(ctx, null, "Missing required fields: " + validation.missing.join(", "));
    }

    var gameId = data.gameId;
    if (!isValidUUID(gameId)) {
        return handleError(ctx, null, "Invalid gameId UUID format");
    }

    var userId = ctx.userId;
    if (!userId) {
        return handleError(ctx, null, "User not authenticated");
    }

    var platform = data.platform;
    var token = data.token;

    // Validate platform
    if (!PLATFORM_TYPES[platform]) {
        return handleError(ctx, null, "Invalid platform. Must be: ios, android, web, or windows");
    }

    logInfo(logger, "Registering " + platform + " push token for user " + userId);

    // Call Lambda to create SNS endpoint
    var lambdaPayload = {
        userId: userId,
        gameId: gameId,
        platform: platform,
        platformType: PLATFORM_TYPES[platform],
        deviceToken: token
    };

    var lambdaResponse;
    try {
        lambdaResponse = nk.httpRequest(
            LAMBDA_FUNCTION_URL,
            "post",
            {
                "Content-Type": "application/json",
                "Accept": "application/json"
            },
            JSON.stringify(lambdaPayload)
        );
    } catch (err) {
        logError(logger, "Lambda request failed: " + err.message);
        return handleError(ctx, err, "Failed to register push token with Lambda");
    }

    if (lambdaResponse.code !== 200 && lambdaResponse.code !== 201) {
        logError(logger, "Lambda returned code " + lambdaResponse.code);
        return handleError(ctx, null, "Lambda endpoint registration failed with code " + lambdaResponse.code);
    }

    var lambdaData;
    try {
        lambdaData = JSON.parse(lambdaResponse.body);
    } catch (err) {
        return handleError(ctx, null, "Invalid Lambda response JSON");
    }

    if (!lambdaData.success || !lambdaData.snsEndpointArn) {
        return handleError(ctx, null, "Lambda did not return endpoint ARN: " + (lambdaData.error || "Unknown error"));
    }

    var endpointArn = lambdaData.snsEndpointArn;

    // Store endpoint ARN
    if (!storeEndpointArn(nk, logger, userId, gameId, platform, endpointArn)) {
        return handleError(ctx, null, "Failed to store endpoint ARN");
    }

    logInfo(logger, "Successfully registered push endpoint: " + endpointArn);

    return JSON.stringify({
        success: true,
        userId: userId,
        gameId: gameId,
        platform: platform,
        endpointArn: endpointArn,
        registeredAt: getCurrentTimestamp()
    });
}

/**
 * RPC: Send push notification event
 * Server-side triggered push notifications
 * 
 * @param {object} ctx - Request context
 * @param {object} logger - Logger instance
 * @param {object} nk - Nakama runtime
 * @param {string} payload - JSON payload with:
 *   {
 *     targetUserId: "uuid",
 *     gameId: "uuid",
 *     eventType: "daily_reward_available|mission_completed|streak_warning|friend_online|etc",
 *     title: "Notification Title",
 *     body: "Notification Body",
 *     data: { custom: "data" }
 *   }
 * @returns {string} JSON response
 */
function rpcPushSendEvent(ctx, logger, nk, payload) {
    logInfo(logger, "RPC push_send_event called");

    var parsed = safeJsonParse(payload);
    if (!parsed.success) {
        return handleError(ctx, null, "Invalid JSON payload");
    }

    var data = parsed.data;
    var validation = validatePayload(data, ['targetUserId', 'gameId', 'eventType', 'title', 'body']);
    if (!validation.valid) {
        return handleError(ctx, null, "Missing required fields: " + validation.missing.join(", "));
    }

    var gameId = data.gameId;
    if (!isValidUUID(gameId)) {
        return handleError(ctx, null, "Invalid gameId UUID format");
    }

    var targetUserId = data.targetUserId;
    var eventType = data.eventType;
    var title = data.title;
    var body = data.body;
    var customData = data.data || {};

    logInfo(logger, "Sending push notification to user " + targetUserId + " for event " + eventType);

    // Get all endpoints for target user
    var endpoints = getAllEndpointArns(nk, logger, targetUserId, gameId);

    if (endpoints.length === 0) {
        return JSON.stringify({
            success: false,
            error: "No registered push endpoints for user"
        });
    }

    var sentCount = 0;
    var errors = [];

    // Send to each endpoint
    for (var i = 0; i < endpoints.length; i++) {
        var endpoint = endpoints[i];

        var pushPayload = {
            endpointArn: endpoint.endpointArn,
            platform: endpoint.platform,
            title: title,
            body: body,
            data: customData,
            gameId: gameId,
            eventType: eventType
        };

        try {
            var lambdaResponse = nk.httpRequest(
                LAMBDA_PUSH_URL,
                "post",
                {
                    "Content-Type": "application/json",
                    "Accept": "application/json"
                },
                JSON.stringify(pushPayload)
            );

            if (lambdaResponse.code === 200 || lambdaResponse.code === 201) {
                sentCount++;
                logInfo(logger, "Push sent to " + endpoint.platform + " endpoint");
            } else {
                errors.push({
                    platform: endpoint.platform,
                    error: "Lambda returned code " + lambdaResponse.code
                });
            }
        } catch (err) {
            errors.push({
                platform: endpoint.platform,
                error: err.message
            });
            logWarn(logger, "Failed to send push to " + endpoint.platform + ": " + err.message);
        }
    }

    // Log notification event
    var notificationLog = {
        targetUserId: targetUserId,
        gameId: gameId,
        eventType: eventType,
        title: title,
        body: body,
        sentCount: sentCount,
        totalEndpoints: endpoints.length,
        timestamp: getCurrentTimestamp()
    };

    var logKey = "push_log_" + targetUserId + "_" + getUnixTimestamp();
    writeStorage(nk, logger, "push_notification_logs", logKey, targetUserId, notificationLog);

    return JSON.stringify({
        success: sentCount > 0,
        targetUserId: targetUserId,
        gameId: gameId,
        eventType: eventType,
        sentCount: sentCount,
        totalEndpoints: endpoints.length,
        errors: errors.length > 0 ? errors : undefined,
        timestamp: getCurrentTimestamp()
    });
}

/**
 * RPC: Get user's registered endpoints
 * @param {object} ctx - Request context
 * @param {object} logger - Logger instance
 * @param {object} nk - Nakama runtime
 * @param {string} payload - JSON payload with { gameId: "uuid" }
 * @returns {string} JSON response
 */
function rpcPushGetEndpoints(ctx, logger, nk, payload) {
    logInfo(logger, "RPC push_get_endpoints called");

    var parsed = safeJsonParse(payload);
    if (!parsed.success) {
        return handleError(ctx, null, "Invalid JSON payload");
    }

    var data = parsed.data;
    var validation = validatePayload(data, ['gameId']);
    if (!validation.valid) {
        return handleError(ctx, null, "Missing required fields: " + validation.missing.join(", "));
    }

    var gameId = data.gameId;
    if (!isValidUUID(gameId)) {
        return handleError(ctx, null, "Invalid gameId UUID format");
    }

    var userId = ctx.userId;
    if (!userId) {
        return handleError(ctx, null, "User not authenticated");
    }

    var endpoints = getAllEndpointArns(nk, logger, userId, gameId);

    return JSON.stringify({
        success: true,
        userId: userId,
        gameId: gameId,
        endpoints: endpoints,
        count: endpoints.length,
        timestamp: getCurrentTimestamp()
    });
}

// Export RPC functions (ES Module syntax)

// ============================================================================
// LEADERBOARD USER PROFILE ENRICHMENT
// ============================================================================
// Production-ready helper to enrich leaderboard records with user profile data
// including avatar URLs, display names, and online status.
// Optimized for performance with batch user lookups and caching.

/**
 * User profile cache (in-memory) for performance
 * Key: userId, Value: { avatarUrl, displayName, online, cachedAt }
 */
var USER_PROFILE_CACHE = {};
var USER_PROFILE_CACHE_TTL = 300000; // 5 minutes cache TTL

/**
 * Batch fetch user profiles by IDs (optimized)
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {string[]} userIds - Array of user IDs to fetch
 * @returns {object} Map of userId -> user profile
 */
function batchGetUserProfiles(nk, logger, userIds) {
    if (!userIds || userIds.length === 0) {
        return {};
    }
    
    var now = Date.now();
    var profileMap = {};
    var uncachedIds = [];
    
    // Check cache first
    for (var i = 0; i < userIds.length; i++) {
        var userId = userIds[i];
        if (!userId) continue;
        
        var cached = USER_PROFILE_CACHE[userId];
        if (cached && (now - cached.cachedAt) < USER_PROFILE_CACHE_TTL) {
            profileMap[userId] = cached;
        } else {
            uncachedIds.push(userId);
        }
    }
    
    // Fetch uncached profiles in batch
    if (uncachedIds.length > 0) {
        try {
            // Use nk.accountsGetId for batch lookup (returns Account objects)
            var accounts = nk.accountsGetId(uncachedIds);
            
            if (accounts && accounts.length > 0) {
                for (var j = 0; j < accounts.length; j++) {
                    var account = accounts[j];
                    if (account && account.user) {
                        var user = account.user;
                        var profile = {
                            avatarUrl: user.avatarUrl || "",
                            displayName: user.displayName || user.username || "",
                            username: user.username || "",
                            online: user.online || false,
                            langTag: user.langTag || "en",
                            location: user.location || "",
                            timezone: user.timezone || "",
                            metadata: user.metadata || "{}",
                            cachedAt: now
                        };
                        profileMap[user.id] = profile;
                        USER_PROFILE_CACHE[user.id] = profile;
                    }
                }
            }
            
            logger.debug("[LeaderboardEnrich] Fetched " + accounts.length + " user profiles, cache hit: " + (userIds.length - uncachedIds.length));
        } catch (err) {
            logger.warn("[LeaderboardEnrich] Failed to batch fetch user profiles: " + err.message);
        }
    }
    
    return profileMap;
}

/**
 * Enrich leaderboard records with user profile data (avatar, displayName, etc.)
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {array} records - Array of leaderboard records from nk.leaderboardRecordsList
 * @returns {array} Enriched records with user profile data
 */
function enrichLeaderboardRecordsWithProfiles(nk, logger, records) {
    if (!records || records.length === 0) {
        return [];
    }
    
    // Collect all unique user IDs
    var userIdSet = {};
    var userIds = [];
    
    for (var i = 0; i < records.length; i++) {
        var record = records[i];
        var ownerId = record.ownerId;
        if (ownerId && !userIdSet[ownerId]) {
            userIdSet[ownerId] = true;
            userIds.push(ownerId);
        }
    }
    
    // Batch fetch all user profiles
    var profileMap = batchGetUserProfiles(nk, logger, userIds);
    
    // Enrich records with profile data
    var enrichedRecords = [];
    
    for (var j = 0; j < records.length; j++) {
        var rec = records[j];
        var profile = profileMap[rec.ownerId] || {};
        
        enrichedRecords.push({
            // Core leaderboard fields
            leaderboardId: rec.leaderboardId || "",
            ownerId: rec.ownerId,
            rank: rec.rank,
            score: rec.score,
            subscore: rec.subscore || 0,
            numScore: rec.numScore || 1,
            maxNumScore: rec.maxNumScore || 0,
            metadata: rec.metadata || "{}",
            createTime: rec.createTime,
            updateTime: rec.updateTime,
            expiryTime: rec.expiryTime || "",
            
            // User profile fields (enriched)
            username: rec.username || profile.username || "",
            displayName: profile.displayName || rec.username || "",
            avatarUrl: profile.avatarUrl || "",
            online: profile.online || false,
            
            // Additional profile info (optional)
            langTag: profile.langTag || "en",
            location: profile.location || "",
            timezone: profile.timezone || ""
        });
    }
    
    logger.info("[LeaderboardEnrich] Enriched " + enrichedRecords.length + " records with user profiles");
    return enrichedRecords;
}

/**
 * Clear user profile cache (call periodically or on user updates)
 * @param {string} userId - Optional: clear specific user; if null, clear all
 */
function clearUserProfileCache(userId) {
    if (userId) {
        delete USER_PROFILE_CACHE[userId];
    } else {
        USER_PROFILE_CACHE = {};
    }
}

/**
 * Enrich session data (compatibility quiz, async challenge) with user avatars
 * Works with sessions that have playerA/playerB structure
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {array} sessions - Array of formatted sessions
 * @returns {array} Sessions enriched with avatar URLs
 */
function enrichSessionsWithAvatars(nk, logger, sessions) {
    if (!sessions || sessions.length === 0) {
        return sessions;
    }
    
    // Collect all unique user IDs from sessions
    var userIdSet = {};
    var userIds = [];
    
    for (var i = 0; i < sessions.length; i++) {
        var session = sessions[i];
        
        // PlayerA
        if (session.playerA && session.playerA.userId) {
            if (!userIdSet[session.playerA.userId]) {
                userIdSet[session.playerA.userId] = true;
                userIds.push(session.playerA.userId);
            }
        }
        
        // PlayerB
        if (session.playerB && session.playerB.userId) {
            if (!userIdSet[session.playerB.userId]) {
                userIdSet[session.playerB.userId] = true;
                userIds.push(session.playerB.userId);
            }
        }
    }
    
    // Batch fetch all user profiles
    var profileMap = batchGetUserProfiles(nk, logger, userIds);
    
    // Enrich sessions with avatar data
    for (var j = 0; j < sessions.length; j++) {
        var sess = sessions[j];
        
        // Enrich PlayerA
        if (sess.playerA && sess.playerA.userId) {
            var profileA = profileMap[sess.playerA.userId];
            if (profileA) {
                sess.playerA.avatarUrl = profileA.avatarUrl || sess.playerA.avatarUrl || '';
                sess.playerA.displayName = sess.playerA.displayName || profileA.displayName || profileA.username || 'Player';
            }
        }
        
        // Enrich PlayerB
        if (sess.playerB && sess.playerB.userId) {
            var profileB = profileMap[sess.playerB.userId];
            if (profileB) {
                sess.playerB.avatarUrl = profileB.avatarUrl || sess.playerB.avatarUrl || '';
                sess.playerB.displayName = sess.playerB.displayName || profileB.displayName || profileB.username || 'Player';
            }
        }
    }
    
    logger.debug("[SessionEnrich] Enriched " + sessions.length + " sessions with user avatars");
    return sessions;
}

/**
 * Enrich a single session with user avatars (for single session returns)
 * @param {object} nk - Nakama runtime
 * @param {object} logger - Logger instance
 * @param {object} session - Single formatted session
 * @returns {object} Session enriched with avatar URLs
 */
function enrichSingleSessionWithAvatars(nk, logger, session) {
    if (!session) return session;
    var enriched = enrichSessionsWithAvatars(nk, logger, [session]);
    return enriched[0];
}

// Export to globalThis for use across modules
if (typeof globalThis !== 'undefined') {
    globalThis.LeaderboardEnrich = {
        batchGetUserProfiles: batchGetUserProfiles,
        enrichRecords: enrichLeaderboardRecordsWithProfiles,
        clearCache: clearUserProfileCache
    };
    globalThis.SessionEnrich = {
        enrichSessions: enrichSessionsWithAvatars,
        enrichSingle: enrichSingleSessionWithAvatars
    };
}

