var COLLECTION_COMPATIBILITY_SESSIONS = 'compatibility_sessions';

/**
 * Generate a unique share code from session ID
 */
function compatibilityGenerateShareCode(sessionId) {
    return sessionId.replace(/-/g, '').substring(0, 8).toUpperCase();
}

/**
 * Send a push notification to a user for compatibility quiz
 */
function compatibilitySendNotification(nk, userId, subject, content, data) {
    try {
        var notifications = [{
            userId: userId,
            subject: subject,
            content: JSON.stringify({
                message: content,
                ...data
            }),
            code: 100,
            persistent: true
        }];
        nk.notificationsSend(notifications);
    } catch (e) {
        // Silently fail if notification fails
    }
}

/**
 * Convert internal session storage to Unity-compatible format
 * Status mapping: 0=WaitingForPartner, 1=PartnerJoined, 2=BothCompleted, 3=Expired, 4=Cancelled
 */
function compatibilitySessionToUnityFormat(session) {
    // Convert string status to numeric
    var statusMap = {
        'waiting_for_partner': 0,
        'partner_joined': 1,
        'creator_completed': 1,
        'partner_completed': 1,
        'both_completed': 2,
        'completed': 2,
        'expired': 3,
        'cancelled': 4
    };
    var numericStatus = typeof session.status === 'number' ? session.status : (statusMap[session.status] || 0);
    
    // Check expiry
    if (Date.now() > session.expiresAt && numericStatus < 2) {
        numericStatus = 3; // Expired
    }
    
    return {
        sessionId: session.sessionId || '',
        quizId: session.quizId || 'compatibility_quiz_v1',
        quizTitle: session.quizTitle || 'Compatibility Quiz',
        createdByUserId: session.creatorId || '',
        createdAt: session.createdAt,
        expiresAt: session.expiresAt,
        playerA: {
            userId: session.creatorId || '',
            displayName: session.creatorName || 'Player A',
            avatarUrl: session.creatorAvatarUrl || '',
            isComplete: session.creatorCompleted || false,
            answers: session.creatorAnswers || [],
            traitScores: session.creatorTraitScores || {},
            resultId: session.creatorResultId || '',
            personalityTitle: session.creatorPersonalityTitle || '',
            personalityEmoji: session.creatorPersonalityEmoji || '',
            completedAt: session.creatorCompletedAt || 0
        },
        playerB: session.partnerId ? {
            userId: session.partnerId || '',
            displayName: session.partnerName || 'Player B',
            avatarUrl: session.partnerAvatarUrl || '',
            isComplete: session.partnerCompleted || false,
            answers: session.partnerAnswers || [],
            traitScores: session.partnerTraitScores || {},
            resultId: session.partnerResultId || '',
            personalityTitle: session.partnerPersonalityTitle || '',
            personalityEmoji: session.partnerPersonalityEmoji || '',
            completedAt: session.partnerCompletedAt || 0
        } : null,
        compatibilityScore: session.compatibilityResult ? session.compatibilityResult.score : 0,
        compatibilityLevel: session.compatibilityResult ? (session.compatibilityResult.level || '') : '',
        matchingTraits: session.compatibilityResult ? (session.compatibilityResult.matchingTraits || []) : [],
        differentTraits: session.compatibilityResult ? (session.compatibilityResult.differentTraits || []) : [],
        compatibilityInsight: session.compatibilityResult ? (session.compatibilityResult.message || '') : '',
        status: numericStatus,
        shareCode: session.shareCode || ''
    };
}

/**
 * Calculate trait similarity between two trait score sets
 */
function compatibilityCalculateTraitSimilarity(traits1, traits2, relevantTraits) {
    var similarity = 0;
    var count = 0;
    
    for (var i = 0; i < relevantTraits.length; i++) {
        var trait = relevantTraits[i];
        var score1 = traits1[trait] || 0;
        var score2 = traits2[trait] || 0;
        
        var norm1 = Math.min(score1 / 5, 1);
        var norm2 = Math.min(score2 / 5, 1);
        
        var diff = Math.abs(norm1 - norm2);
        similarity += (1 - diff);
        count++;
    }
    
    return count > 0 ? similarity / count : 0.5;
}

/**
 * Count how many answers match between two players
 */
function compatibilityCountMatchingAnswers(answers1, answers2) {
    var matches = 0;
    var minLen = Math.min(answers1.length, answers2.length);
    
    for (var i = 0; i < minLen; i++) {
        var a1 = answers1[i];
        var a2 = answers2[i];
        
        if (a1 && a2 && a1.optionId === a2.optionId) {
            matches++;
        }
    }
    
    return matches;
}

/**
 * Compute compatibility score based on trait scores and answers
 */
function compatibilityComputeScore(creatorTraits, partnerTraits, creatorAnswers, partnerAnswers) {
    var totalScore = 0;
    var categoryCount = 0;
    var breakdown = {};
    
    // 1. Communication Style
    var commScore = compatibilityCalculateTraitSimilarity(
        creatorTraits,
        partnerTraits,
        ['mbti:E', 'mbti:I', 'mbti:J', 'mbti:P']
    );
    breakdown.communicationStyle = Math.round(commScore * 100);
    totalScore += commScore;
    categoryCount++;
    
    // 2. Emotional Connection
    var emotionalScore = compatibilityCalculateTraitSimilarity(
        creatorTraits,
        partnerTraits,
        ['mbti:F', 'mbti:T', 'big_five:high_agreeableness', 'big_five:high_openness']
    );
    breakdown.emotionalConnection = Math.round(emotionalScore * 100);
    totalScore += emotionalScore;
    categoryCount++;
    
    // 3. Shared Values
    var valuesScore = compatibilityCalculateTraitSimilarity(
        creatorTraits,
        partnerTraits,
        ['mbti:N', 'mbti:S', 'big_five:high_conscientiousness']
    );
    breakdown.sharedValues = Math.round(valuesScore * 100);
    totalScore += valuesScore;
    categoryCount++;
    
    // 4. Direct answer matching bonus
    var matchingAnswers = compatibilityCountMatchingAnswers(creatorAnswers, partnerAnswers);
    var maxLen = Math.max(creatorAnswers.length, partnerAnswers.length, 1);
    var matchRatio = matchingAnswers / maxLen;
    breakdown.answerAlignment = Math.round(matchRatio * 100);
    totalScore += matchRatio * 0.5;
    categoryCount += 0.5;
    
    var finalScore = (totalScore / categoryCount) * 100;
    
    var message;
    var emoji;
    if (finalScore >= 90) {
        message = "You're a perfect match! Your connection is extraordinary!";
        emoji = "heart";
    } else if (finalScore >= 75) {
        message = "Highly compatible! You complement each other wonderfully!";
        emoji = "hearts";
    } else if (finalScore >= 60) {
        message = "Good compatibility! You share many common values!";
        emoji = "heart_pink";
    } else if (finalScore >= 45) {
        message = "Moderate compatibility! Opposites can attract!";
        emoji = "heart_yellow";
    } else {
        message = "Different perspectives! Diversity makes life interesting!";
        emoji = "star";
    }
    
    // Determine compatibility level string
    var level;
    if (finalScore >= 90) {
        level = "Perfect Match";
    } else if (finalScore >= 75) {
        level = "Highly Compatible";
    } else if (finalScore >= 60) {
        level = "Good Match";
    } else if (finalScore >= 45) {
        level = "Moderate";
    } else {
        level = "Different Perspectives";
    }
    
    // Generate matching traits based on category scores
    var matchingTraits = [];
    var differentTraits = [];
    
    if (breakdown.communicationStyle >= 70) {
        matchingTraits.push("Communication Style");
    } else if (breakdown.communicationStyle < 40) {
        differentTraits.push("Communication Style");
    }
    
    if (breakdown.emotionalConnection >= 70) {
        matchingTraits.push("Emotional Connection");
    } else if (breakdown.emotionalConnection < 40) {
        differentTraits.push("Emotional Connection");
    }
    
    if (breakdown.sharedValues >= 70) {
        matchingTraits.push("Shared Values");
    } else if (breakdown.sharedValues < 40) {
        differentTraits.push("Shared Values");
    }
    
    if (breakdown.answerAlignment >= 60) {
        matchingTraits.push("Similar Thinking");
    } else if (breakdown.answerAlignment < 30) {
        differentTraits.push("Different Viewpoints");
    }
    
    // Add personality-based traits
    if (creatorTraits['mbti:E'] && partnerTraits['mbti:E'] && 
        creatorTraits['mbti:E'] > 2 && partnerTraits['mbti:E'] > 2) {
        matchingTraits.push("Both Outgoing");
    }
    if (creatorTraits['mbti:I'] && partnerTraits['mbti:I'] && 
        creatorTraits['mbti:I'] > 2 && partnerTraits['mbti:I'] > 2) {
        matchingTraits.push("Both Thoughtful");
    }
    if (creatorTraits['big_five:high_openness'] && partnerTraits['big_five:high_openness'] &&
        creatorTraits['big_five:high_openness'] > 2 && partnerTraits['big_five:high_openness'] > 2) {
        matchingTraits.push("Creative Minds");
    }
    if (creatorTraits['big_five:high_agreeableness'] && partnerTraits['big_five:high_agreeableness'] &&
        creatorTraits['big_five:high_agreeableness'] > 2 && partnerTraits['big_five:high_agreeableness'] > 2) {
        matchingTraits.push("Caring Hearts");
    }
    
    // Ensure we have at least one matching trait or different trait
    if (matchingTraits.length === 0 && finalScore >= 50) {
        matchingTraits.push("Open to Growth");
    }
    if (differentTraits.length === 0 && finalScore < 50) {
        differentTraits.push("Unique Perspectives");
    }
    
    // Format category scores for Unity frontend
    var categoryScores = {
        communication: breakdown.communicationStyle || 0,
        emotional: breakdown.emotionalConnection || 0,
        values: breakdown.sharedValues || 0,
        lifestyle: Math.round((breakdown.answerAlignment || 0) * 0.8), // Derive lifestyle from answer alignment
        interests: Math.round(finalScore * 0.9) // Derive interests from overall score
    };
    
    // Generate growth areas from low-scoring categories
    var growthAreas = [];
    if (categoryScores.communication < 50) growthAreas.push("Communication Skills");
    if (categoryScores.emotional < 50) growthAreas.push("Emotional Understanding");
    if (categoryScores.values < 50) growthAreas.push("Aligning Core Values");
    if (categoryScores.lifestyle < 50) growthAreas.push("Lifestyle Balance");
    if (categoryScores.interests < 50) growthAreas.push("Discovering Shared Interests");
    
    // Ensure at least one growth area
    if (growthAreas.length === 0) {
        growthAreas.push("Keep Growing Together");
    }
    
    // Generate relationship advice based on score
    var relationshipAdvice;
    if (finalScore >= 85) {
        relationshipAdvice = "Your connection is truly special! Keep nurturing this beautiful bond. 💕";
    } else if (finalScore >= 70) {
        relationshipAdvice = "You have great potential together. Communication is your superpower! 💖";
    } else if (finalScore >= 55) {
        relationshipAdvice = "Embrace your differences - they make your relationship unique! 💗";
    } else if (finalScore >= 40) {
        relationshipAdvice = "Every relationship is a journey of discovery. Keep exploring together! 💛";
    } else {
        relationshipAdvice = "Your different perspectives can lead to amazing growth. Stay curious! 🌟";
    }
    
    return {
        score: finalScore,
        overallScore: finalScore, // Alias for Unity compatibility
        level: level,
        compatibilityLevel: level, // Alias for Unity compatibility
        breakdown: breakdown,
        categoryScores: categoryScores,
        message: message,
        relationshipAdvice: relationshipAdvice, // Explicit advice field for Unity
        compatibilityInsight: message, // Alias for backward compatibility
        emoji: emoji,
        matchingTraits: matchingTraits,
        differentTraits: differentTraits,
        growthAreas: growthAreas,
        matchingAnswers: matchingAnswers,
        totalQuestions: maxLen
    };
}

/**
 * RPC: Create a new compatibility quiz session
 * Payload: { quizId: string, userId?: string, playerDisplayName?: string }
 */
function rpcCompatibilityCreateSession(ctx, logger, nk, payload) {
    logger.debug('[CompatibilityQuiz] Creating session for user: ' + ctx.userId);
    
    var request;
    try {
        request = JSON.parse(payload || '{}');
    } catch (e) {
        return JSON.stringify({ success: false, message: 'Invalid JSON payload', data: null });
    }
    
    try {
        // CRITICAL: Validate userId - use from context or fallback to payload
        var userId = ctx.userId;
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            userId = request.userId;
        }
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            return JSON.stringify({ 
                success: false, 
                message: 'User authentication required. Please ensure you are logged in.', 
                data: null,
                errorCode: 'AUTH_REQUIRED'
            });
        }
        
        var quizId = request.quizId || 'compatibility_quiz_v1';
        var quizTitle = request.quizTitle || 'Compatibility Quiz';
        var playerDisplayName = request.playerDisplayName || 'Unknown';
        var sessionId = nk.uuidv4();
        var shareCode = compatibilityGenerateShareCode(sessionId);
        var now = Date.now();
        var expiresAt = now + (48 * 60 * 60 * 1000);
        
        // Fetch user display name (with fallback)
        var displayName = playerDisplayName;
        try {
            var users = nk.usersGetId([userId]);
            if (users && users.length > 0) {
                displayName = users[0].displayName || users[0].username || playerDisplayName;
            }
        } catch (userErr) {
            logger.warn('[CompatibilityQuiz] Could not fetch user info: ' + userErr.message);
        }
        
        // Internal storage format
        var sessionStorage = {
            sessionId: sessionId,
            shareCode: shareCode,
            quizId: quizId,
            quizTitle: quizTitle,
            creatorId: userId,
            creatorName: displayName,
            partnerId: null,
            partnerName: null,
            status: 0, // WaitingForPartner
            createdAt: now,
            expiresAt: expiresAt,
            creatorCompleted: false,
            partnerCompleted: false,
            creatorAnswers: null,
            partnerAnswers: null,
            creatorTraitScores: null,
            partnerTraitScores: null,
            compatibilityResult: null
        };
        
        nk.storageWrite([{
            collection: COLLECTION_COMPATIBILITY_SESSIONS,
            key: sessionId,
            userId: userId,
            value: sessionStorage,
            permissionRead: 2,
            permissionWrite: 1
        }]);
        
        // Store code mapping with system user ID for public lookup
        nk.storageWrite([{
            collection: COLLECTION_COMPATIBILITY_SESSIONS,
            key: 'code_' + shareCode,
            userId: '00000000-0000-0000-0000-000000000000',
            value: { sessionId: sessionId, creatorId: userId },
            permissionRead: 2,
            permissionWrite: 0
        }]);
        
        logger.info('[CompatibilityQuiz] Session created: ' + sessionId + ' with code: ' + shareCode);
        
        // Response format matching Unity client expectations
        return JSON.stringify({
            success: true,
            message: 'Session created successfully',
            data: {
                sessionId: sessionId,
                quizId: quizId,
                quizTitle: quizTitle,
                createdByUserId: ctx.userId,
                createdAt: now,
                expiresAt: expiresAt,
                playerA: {
                    userId: ctx.userId,
                    displayName: displayName,
                    isComplete: false,
                    answeredQuestions: [],
                    traitScores: {}
                },
                playerB: null,
                compatibilityScore: 0,
                compatibilityLevel: null,
                matchingTraits: [],
                differentTraits: [],
                compatibilityInsight: null,
                status: 0, // WaitingForPartner
                shareCode: shareCode
            }
        });
    } catch (err) {
        logger.error('[CompatibilityQuiz] Create session error: ' + err.message);
        return JSON.stringify({ success: false, message: err.message, data: null });
    }
}

/**
 * RPC: Join an existing compatibility quiz session
 * Payload: { shareCode: string, userId?: string, playerDisplayName?: string }
 */
function rpcCompatibilityJoinSession(ctx, logger, nk, payload) {
    logger.debug('[CompatibilityQuiz] User ' + ctx.userId + ' attempting to join session');
    
    var request;
    try {
        request = JSON.parse(payload || '{}');
    } catch (e) {
        return JSON.stringify({ success: false, message: 'Invalid JSON payload', data: null });
    }
    
    try {
        // CRITICAL: Validate userId - use from context or fallback to payload
        var userId = ctx.userId;
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            userId = request.userId;
        }
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            return JSON.stringify({ 
                success: false, 
                message: 'User authentication required. Please ensure you are logged in.', 
                data: null,
                errorCode: 'AUTH_REQUIRED'
            });
        }
        
        var shareCode = (request.shareCode || request.shareCodeOrSessionId || '').toUpperCase().trim();
        if (!shareCode || shareCode.length < 6) {
            return JSON.stringify({ success: false, message: 'Invalid share code', data: null });
        }
        
        // Note: We must read using the creator's ID, but we don't know it yet.
        // First, try to find the code record by listing storage with the code key pattern.
        // For now, we'll use a different approach - store the code mapping with system user.
        var codeResults = nk.storageRead([{
            collection: COLLECTION_COMPATIBILITY_SESSIONS,
            key: 'code_' + shareCode,
            userId: '00000000-0000-0000-0000-000000000000'
        }]);
        
        if (codeResults.length === 0) {
            return JSON.stringify({ success: false, message: 'Session not found', data: null });
        }
        
        var codeRecord = codeResults[0].value;
        var sessionId = codeRecord.sessionId;
        var creatorId = codeRecord.creatorId;
        
        var sessionResults = nk.storageRead([{
            collection: COLLECTION_COMPATIBILITY_SESSIONS,
            key: sessionId,
            userId: creatorId
        }]);
        
        if (sessionResults.length === 0) {
            return JSON.stringify({ success: false, message: 'Session data not found', data: null });
        }
        
        var session = sessionResults[0].value;
        
        if (session.status === 3 || session.status === 'expired' || Date.now() > session.expiresAt) {
            return JSON.stringify({ success: false, message: 'Session has expired', data: null });
        }
        
        if (session.partnerId !== null && session.partnerId !== userId) {
            return JSON.stringify({ success: false, message: 'Session already has a partner', data: null });
        }
        
        if (session.creatorId === userId) {
            return JSON.stringify({ success: false, message: 'Cannot join your own session', data: null });
        }
        
        // Fetch user display name (with fallback)
        var displayName = request.playerDisplayName || 'Unknown';
        try {
            var users = nk.usersGetId([userId]);
            if (users && users.length > 0) {
                displayName = users[0].displayName || users[0].username || displayName;
            }
        } catch (userErr) {
            logger.warn('[CompatibilityQuiz] Could not fetch user info: ' + userErr.message);
        }
        
        session.partnerId = userId;
        session.partnerName = displayName;
        session.status = 1; // PartnerJoined
        
        nk.storageWrite([{
            collection: COLLECTION_COMPATIBILITY_SESSIONS,
            key: sessionId,
            userId: creatorId,
            value: session,
            permissionRead: 2,
            permissionWrite: 1
        }]);
        
        compatibilitySendNotification(nk, session.creatorId,
            'Partner Joined!',
            displayName + ' has joined your compatibility quiz!',
            { type: 'partner_joined', sessionId: sessionId }
        );
        
        logger.info('[CompatibilityQuiz] User ' + userId + ' joined session ' + sessionId);
        
        // Format and enrich with avatar URLs
        var formattedSession = compatibilitySessionToUnityFormat(session);
        formattedSession = enrichSingleSessionWithAvatars(nk, logger, formattedSession);
        
        return JSON.stringify({
            success: true,
            message: 'Successfully joined session',
            data: formattedSession
        });
    } catch (err) {
        logger.error('[CompatibilityQuiz] Join session error: ' + err.message);
        return JSON.stringify({ success: false, message: err.message, data: null });
    }
}

/**
 * RPC: Get session details
 * Payload: { sessionId: string, userId?: string } or { shareCode: string, userId?: string }
 */
function rpcCompatibilityGetSession(ctx, logger, nk, payload) {
    var request;
    try {
        request = JSON.parse(payload || '{}');
    } catch (e) {
        return JSON.stringify({ success: false, message: 'Invalid JSON payload', data: null });
    }
    
    try {
        // CRITICAL: Validate userId - use from context or fallback to payload
        var userId = ctx.userId;
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            userId = request.userId;
        }
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            return JSON.stringify({ 
                success: false, 
                message: 'User authentication required. Please ensure you are logged in.', 
                data: null,
                errorCode: 'AUTH_REQUIRED'
            });
        }
        
        var sessionId = request.sessionId;
        var creatorId = null;
        
        if (!sessionId && request.shareCode) {
            var shareCode = request.shareCode.toUpperCase().trim();
            var codeResults = nk.storageRead([{
                collection: COLLECTION_COMPATIBILITY_SESSIONS,
                key: 'code_' + shareCode,
                userId: '00000000-0000-0000-0000-000000000000'
            }]);
            
            if (codeResults.length === 0) {
                return JSON.stringify({ success: false, message: 'Session not found', data: null });
            }
            
            sessionId = codeResults[0].value.sessionId;
            creatorId = codeResults[0].value.creatorId;
        }
        
        var sessionResults = nk.storageRead([{
            collection: COLLECTION_COMPATIBILITY_SESSIONS,
            key: sessionId,
            userId: userId
        }]);
        
        if (sessionResults.length === 0 && creatorId) {
            sessionResults = nk.storageRead([{
                collection: COLLECTION_COMPATIBILITY_SESSIONS,
                key: sessionId,
                userId: creatorId
            }]);
        }
        
        if (sessionResults.length === 0) {
            return JSON.stringify({ success: false, message: 'Session not found', data: null });
        }
        
        var session = sessionResults[0].value;
        
        if (session.creatorId !== userId && session.partnerId !== userId) {
            return JSON.stringify({ success: false, message: 'Not authorized to view this session', data: null });
        }
        
        // Format and enrich with avatar URLs
        var formattedSession = compatibilitySessionToUnityFormat(session);
        formattedSession = enrichSingleSessionWithAvatars(nk, logger, formattedSession);
        
        return JSON.stringify({
            success: true,
            message: 'Session retrieved',
            data: formattedSession
        });
    } catch (err) {
        logger.error('[CompatibilityQuiz] Get session error: ' + err.message);
        return JSON.stringify({ success: false, message: err.message, data: null });
    }
}

/**
 * RPC: Submit quiz answers
 * Payload: { sessionId, answers[], traitScores{} }
 */
function rpcCompatibilitySubmitAnswers(ctx, logger, nk, payload) {
    logger.debug('[CompatibilityQuiz] User ' + ctx.userId + ' submitting answers');
    
    var request;
    try {
        request = JSON.parse(payload || '{}');
    } catch (e) {
        return JSON.stringify({ success: false, message: 'Invalid JSON payload', data: null });
    }
    
    try {
        // CRITICAL: Validate userId - use from context or fallback to payload
        var userId = ctx.userId;
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            userId = request.userId;
        }
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            return JSON.stringify({ 
                success: false, 
                message: 'User authentication required. Please ensure you are logged in.', 
                data: null,
                errorCode: 'AUTH_REQUIRED'
            });
        }
        
        var sessionId = request.sessionId;
        var answers = request.answers || [];
        var traitScores = request.traitScores || {};
        
        if (!sessionId) {
            return JSON.stringify({ success: false, message: 'Session ID required', data: null });
        }
        
        var sessionResults = nk.storageRead([{
            collection: COLLECTION_COMPATIBILITY_SESSIONS,
            key: sessionId,
            userId: userId
        }]);
        
        var isCreator = sessionResults.length > 0;
        var creatorId = isCreator ? userId : null;
        
        if (!isCreator) {
            var listResults = nk.storageList(null, COLLECTION_COMPATIBILITY_SESSIONS, 100, '');
            var objects = listResults.objects || [];
            
            for (var i = 0; i < objects.length; i++) {
                var obj = objects[i];
                if (obj.value.sessionId === sessionId && obj.value.partnerId === userId) {
                    creatorId = obj.value.creatorId;
                    break;
                }
            }
            
            if (creatorId) {
                sessionResults = nk.storageRead([{
                    collection: COLLECTION_COMPATIBILITY_SESSIONS,
                    key: sessionId,
                    userId: creatorId
                }]);
            }
        }
        
        if (sessionResults.length === 0) {
            return JSON.stringify({ success: false, message: 'Session not found', data: null });
        }
        
        var session = sessionResults[0].value;
        
        var isPartner = session.partnerId === userId;
        isCreator = session.creatorId === userId;
        
        if (!isCreator && !isPartner) {
            return JSON.stringify({ success: false, message: 'Not authorized for this session', data: null });
        }
        
        var now = Date.now();
        if (isCreator) {
            session.creatorAnswers = answers;
            session.creatorTraitScores = traitScores;
            session.creatorCompleted = true;
            session.creatorCompletedAt = now;
            session.creatorResultId = request.resultId || null;
            session.creatorPersonalityTitle = request.personalityTitle || null;
            session.creatorPersonalityEmoji = request.personalityEmoji || null;
        } else {
            session.partnerAnswers = answers;
            session.partnerTraitScores = traitScores;
            session.partnerCompleted = true;
            session.partnerCompletedAt = now;
            session.partnerResultId = request.resultId || null;
            session.partnerPersonalityTitle = request.personalityTitle || null;
            session.partnerPersonalityEmoji = request.personalityEmoji || null;
        }
        
        // Update status using numeric values
        if (session.creatorCompleted && session.partnerCompleted) {
            session.status = 2; // BothCompleted
        } else if (session.creatorCompleted || session.partnerCompleted) {
            session.status = 1; // PartnerJoined (or waiting for other)
        }
        
        nk.storageWrite([{
            collection: COLLECTION_COMPATIBILITY_SESSIONS,
            key: sessionId,
            userId: session.creatorId,
            value: session,
            permissionRead: 2,
            permissionWrite: 1
        }]);
        
        if (isCreator && session.partnerId) {
            compatibilitySendNotification(nk, session.partnerId,
                'Your partner finished!',
                session.creatorName + ' completed the quiz. Check your results!',
                { type: 'creator_completed', sessionId: sessionId }
            );
        } else if (isPartner) {
            compatibilitySendNotification(nk, session.creatorId,
                'Results are ready!',
                session.partnerName + ' completed the quiz! See your compatibility now!',
                { type: 'partner_completed', sessionId: sessionId }
            );
        }
        
        logger.info('[CompatibilityQuiz] Answers submitted for session ' + sessionId);
        
        // Format and enrich with avatar URLs
        var formattedSession = compatibilitySessionToUnityFormat(session);
        formattedSession = enrichSingleSessionWithAvatars(nk, logger, formattedSession);
        
        return JSON.stringify({
            success: true,
            message: 'Answers submitted successfully',
            data: formattedSession
        });
    } catch (err) {
        logger.error('[CompatibilityQuiz] Submit answers error: ' + err.message);
        return JSON.stringify({ success: false, message: err.message, data: null });
    }
}

/**
 * RPC: Calculate compatibility between two players
 * Payload: { sessionId: string }
 */
function rpcCompatibilityCalculate(ctx, logger, nk, payload) {
    logger.debug('[CompatibilityQuiz] Calculating compatibility for user ' + ctx.userId);
    
    var request;
    try {
        request = JSON.parse(payload || '{}');
    } catch (e) {
        return JSON.stringify({ success: false, message: 'Invalid JSON payload', data: null });
    }
    
    try {
        // CRITICAL: Validate userId - use from context or fallback to payload
        var userId = ctx.userId;
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            userId = request.userId;
        }
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            return JSON.stringify({ 
                success: false, 
                message: 'User authentication required. Please ensure you are logged in.', 
                data: null,
                errorCode: 'AUTH_REQUIRED'
            });
        }
        
        var sessionId = request.sessionId;
        if (!sessionId) {
            return JSON.stringify({ success: false, message: 'Session ID required', data: null });
        }
        
        var sessionResults = nk.storageRead([{
            collection: COLLECTION_COMPATIBILITY_SESSIONS,
            key: sessionId,
            userId: userId
        }]);
        
        var creatorId = userId;
        
        if (sessionResults.length === 0) {
            var listResults = nk.storageList(null, COLLECTION_COMPATIBILITY_SESSIONS, 100, '');
            var objects = listResults.objects || [];
            
            for (var i = 0; i < objects.length; i++) {
                var obj = objects[i];
                if (obj.value.sessionId === sessionId) {
                    creatorId = obj.value.creatorId;
                    break;
                }
            }
            
            sessionResults = nk.storageRead([{
                collection: COLLECTION_COMPATIBILITY_SESSIONS,
                key: sessionId,
                userId: creatorId
            }]);
        }
        
        if (sessionResults.length === 0) {
            return JSON.stringify({ success: false, message: 'Session not found', data: null });
        }
        
        var session = sessionResults[0].value;
        
        if (!session.creatorCompleted || !session.partnerCompleted) {
            return JSON.stringify({ success: false, message: 'Both players must complete the quiz first', data: null });
        }
        
        // If already calculated, return cached result
        if (session.compatibilityResult) {
            session.status = 2; // BothCompleted
            var cachedSession = compatibilitySessionToUnityFormat(session);
            cachedSession = enrichSingleSessionWithAvatars(nk, logger, cachedSession);
            return JSON.stringify({
                success: true,
                message: 'Compatibility result retrieved',
                data: cachedSession
            });
        }
        
        var creatorTraits = session.creatorTraitScores || {};
        var partnerTraits = session.partnerTraitScores || {};
        var creatorAnswers = session.creatorAnswers || [];
        var partnerAnswers = session.partnerAnswers || [];
        
        var result = compatibilityComputeScore(creatorTraits, partnerTraits, creatorAnswers, partnerAnswers);
        
        session.compatibilityResult = result;
        session.status = 2; // BothCompleted
        
        nk.storageWrite([{
            collection: COLLECTION_COMPATIBILITY_SESSIONS,
            key: sessionId,
            userId: creatorId,
            value: session,
            permissionRead: 2,
            permissionWrite: 1
        }]);
        
        var resultMessage = 'Your compatibility score: ' + result.score.toFixed(0) + '%!';
        
        compatibilitySendNotification(nk, session.creatorId,
            'Compatibility Results!',
            resultMessage,
            { type: 'results_ready', sessionId: sessionId }
        );
        
        if (session.partnerId) {
            compatibilitySendNotification(nk, session.partnerId,
                'Compatibility Results!',
                resultMessage,
                { type: 'results_ready', sessionId: sessionId }
            );
        }
        
        logger.info('[CompatibilityQuiz] Compatibility calculated: ' + result.score + '%');
        
        // Format and enrich with avatar URLs
        var calculatedSession = compatibilitySessionToUnityFormat(session);
        calculatedSession = enrichSingleSessionWithAvatars(nk, logger, calculatedSession);
        
        return JSON.stringify({
            success: true,
            message: 'Compatibility calculated',
            data: calculatedSession
        });
    } catch (err) {
        logger.error('[CompatibilityQuiz] Calculate error: ' + err.message);
        return JSON.stringify({ success: false, message: err.message, data: null });
    }
}

/**
 * RPC: List user's compatibility sessions
 * Payload: { limit?: number, includeExpired?: boolean, userId?: string }
 */
function rpcCompatibilityListSessions(ctx, logger, nk, payload) {
    var request = {};
    try {
        if (payload) {
            request = JSON.parse(payload);
        }
    } catch (e) {
        // Use defaults
    }
    
    try {
        // CRITICAL: Validate userId - use from context or fallback to payload
        var userId = ctx.userId;
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            userId = request.userId;
        }
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            return JSON.stringify({ 
                success: false, 
                message: 'User authentication required. Please ensure you are logged in.', 
                data: [],
                errorCode: 'AUTH_REQUIRED'
            });
        }
        
        var limit = Math.min(request.limit || 20, 100);
        var includeExpired = request.includeExpired || false;
        
        var creatorSessions = nk.storageList(userId, COLLECTION_COMPATIBILITY_SESSIONS, limit, '');
        
        var sessions = [];
        var now = Date.now();
        var objects = creatorSessions.objects || [];
        
        for (var i = 0; i < objects.length; i++) {
            var obj = objects[i];
            var session = obj.value;
            
            if (obj.key.indexOf('code_') === 0) continue;
            
            // Convert status to numeric
            var numericStatus = typeof session.status === 'number' ? session.status : 0;
            var isExpired = numericStatus === 3 || now > session.expiresAt;
            
            if (!includeExpired && isExpired) {
                continue;
            }
            
            sessions.push(compatibilitySessionToUnityFormat(session));
        }
        
        // Enrich sessions with avatar URLs
        sessions = enrichSessionsWithAvatars(nk, logger, sessions);
        
        return JSON.stringify({
            success: true,
            message: 'Sessions retrieved',
            data: sessions
        });
    } catch (err) {
        logger.error('[CompatibilityQuiz] List sessions error: ' + err.message);
        return JSON.stringify({ success: false, message: err.message, data: [] });
    }
}

// ============================================================================
// ASYNC CHALLENGE SYSTEM - Universal Async Quiz Challenge (All Quiz Modes)
// ============================================================================
// Allows any player to challenge a friend to any quiz mode asynchronously.
// Player A creates challenge → plays quiz → shares code → Player B joins → plays
// When both complete, results compared and notifications sent.
// Integrates with: Chat, Friends, Native Share, Push Notifications
// ============================================================================

var COLLECTION_ASYNC_CHALLENGES = 'async_challenges';

/**
 * Generate a unique 6-char alphanumeric share code from session ID
 * Uses uppercase letters + digits, excludes ambiguous chars (0/O, 1/I/L)
 */
function asyncChallengeGenerateShareCode(sessionId) {
    var chars = 'ABCDEFGHJKMNPQRSTUVWXYZ23456789';
    var hash = sessionId.replace(/-/g, '');
    var code = '';
    for (var i = 0; i < 6; i++) {
        var idx = parseInt(hash.substring(i * 2, i * 2 + 2), 16) % chars.length;
        code += chars.charAt(idx);
    }
    return code;
}

/**
 * Send notification to a user for async challenge events
 */
function asyncChallengeSendNotification(nk, logger, userId, subject, content, data) {
    try {
        var notifications = [{
            userId: userId,
            subject: subject,
            content: JSON.stringify({
                message: content,
                type: 'async_challenge',
                ...data
            }),
            code: 100,
            persistent: true
        }];
        nk.notificationsSend(notifications);
    } catch (e) {
        if (logger) logger.warn('[AsyncChallenge] Notification send failed: ' + e.message);
    }
}

/**
 * Convert internal session storage to Unity-compatible format
 * Status mapping: 0=WaitingForOpponent, 1=OpponentJoined, 2=BothCompleted, 3=Expired, 4=Cancelled
 */
function asyncChallengeToUnityFormat(session) {
    var now = Date.now();
    var status = typeof session.status === 'number' ? session.status : 0;

    // Auto-expire if past deadline and not yet completed
    if (now > session.expiresAt && status < 2) {
        status = 3; // Expired
    }

    var result = {
        sessionId: session.sessionId || '',
        shareCode: session.shareCode || '',
        quizModeType: session.quizModeType || 0,
        quizModeName: session.quizModeName || '',
        quizConfig: session.quizConfig || null,
        gameId: session.gameId || '',
        status: status,
        createdAt: session.createdAt || 0,
        expiresAt: session.expiresAt || 0,
        challengedUserId: session.challengedId || null,
        playerA: {
            userId: session.creatorId || '',
            displayName: session.creatorName || 'Player',
            avatarUrl: session.creatorAvatarUrl || '',
            isComplete: session.creatorResult ? session.creatorResult.isComplete : false,
            score: session.creatorResult ? (session.creatorResult.score || 0) : 0,
            correctAnswers: session.creatorResult ? (session.creatorResult.correctAnswers || 0) : 0,
            totalQuestions: session.creatorResult ? (session.creatorResult.totalQuestions || 0) : 0,
            timeTaken: session.creatorResult ? (session.creatorResult.timeTaken || 0) : 0,
            completedAt: session.creatorResult ? (session.creatorResult.completedAt || 0) : 0,
            accuracy: session.creatorResult ? (session.creatorResult.accuracy || 0) : 0
        },
        playerB: session.opponentId ? {
            userId: session.opponentId || '',
            displayName: session.opponentName || 'Player',
            avatarUrl: session.opponentAvatarUrl || '',
            isComplete: session.opponentResult ? session.opponentResult.isComplete : false,
            score: session.opponentResult ? (session.opponentResult.score || 0) : 0,
            correctAnswers: session.opponentResult ? (session.opponentResult.correctAnswers || 0) : 0,
            totalQuestions: session.opponentResult ? (session.opponentResult.totalQuestions || 0) : 0,
            timeTaken: session.opponentResult ? (session.opponentResult.timeTaken || 0) : 0,
            completedAt: session.opponentResult ? (session.opponentResult.completedAt || 0) : 0,
            accuracy: session.opponentResult ? (session.opponentResult.accuracy || 0) : 0
        } : null,
        finalResult: session.finalResult || null
    };

    return result;
}

/**
 * Compute challenge winner and comparison results
 */
function asyncChallengeComputeResult(session) {
    var cResult = session.creatorResult || {};
    var oResult = session.opponentResult || {};

    var creatorScore = cResult.score || 0;
    var opponentScore = oResult.score || 0;
    var scoreDiff = Math.abs(creatorScore - opponentScore);

    var winnerId = null;
    var winnerName = null;
    var loserId = null;
    var loserName = null;
    var isDraw = false;

    if (creatorScore > opponentScore) {
        winnerId = session.creatorId;
        winnerName = session.creatorName;
        loserId = session.opponentId;
        loserName = session.opponentName;
    } else if (opponentScore > creatorScore) {
        winnerId = session.opponentId;
        winnerName = session.opponentName;
        loserId = session.creatorId;
        loserName = session.creatorName;
    } else {
        // Draw — tiebreak by time (faster wins)
        var creatorTime = cResult.timeTaken || 999999;
        var opponentTime = oResult.timeTaken || 999999;
        if (creatorTime < opponentTime) {
            winnerId = session.creatorId;
            winnerName = session.creatorName;
            loserId = session.opponentId;
            loserName = session.opponentName;
        } else if (opponentTime < creatorTime) {
            winnerId = session.opponentId;
            winnerName = session.opponentName;
            loserId = session.creatorId;
            loserName = session.creatorName;
        } else {
            isDraw = true;
        }
    }

    // Build comparison breakdown
    var creatorAccuracy = cResult.totalQuestions > 0 ? (cResult.correctAnswers / cResult.totalQuestions * 100) : 0;
    var opponentAccuracy = oResult.totalQuestions > 0 ? (oResult.correctAnswers / oResult.totalQuestions * 100) : 0;

    var message;
    if (isDraw) {
        message = "It's a perfect draw! You both scored " + creatorScore + " points!";
    } else if (scoreDiff >= 500) {
        message = winnerName + " dominated with a " + scoreDiff + " point lead!";
    } else if (scoreDiff >= 200) {
        message = winnerName + " won convincingly by " + scoreDiff + " points!";
    } else if (scoreDiff >= 50) {
        message = winnerName + " edged ahead by " + scoreDiff + " points!";
    } else {
        message = "Incredibly close! " + winnerName + " won by just " + scoreDiff + " points!";
    }

    return {
        winnerId: winnerId,
        winnerName: winnerName || '',
        loserId: loserId,
        loserName: loserName || '',
        isDraw: isDraw,
        scoreDifference: scoreDiff,
        creatorScore: creatorScore,
        opponentScore: opponentScore,
        creatorAccuracy: Math.round(creatorAccuracy * 10) / 10,
        opponentAccuracy: Math.round(opponentAccuracy * 10) / 10,
        creatorTimeTaken: cResult.timeTaken || 0,
        opponentTimeTaken: oResult.timeTaken || 0,
        message: message
    };
}

/**
 * RPC: Create a new async challenge
 * Payload: {
 *   quizModeType: number,
 *   quizModeName: string,
 *   quizConfig?: object,
 *   challengedUserId?: string,
 *   challengedDisplayName?: string,
 *   playerDisplayName?: string,
 *   userId?: string
 * }
 */
function rpcAsyncChallengeCreate(ctx, logger, nk, payload) {
    logger.debug('[AsyncChallenge] Creating challenge for user: ' + ctx.userId);

    var request;
    try {
        request = JSON.parse(payload || '{}');
    } catch (e) {
        return JSON.stringify({ success: false, message: 'Invalid JSON payload', data: null });
    }

    try {
        // Auth validation
        var userId = ctx.userId;
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            userId = request.userId;
        }
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            return JSON.stringify({
                success: false,
                message: 'User authentication required. Please ensure you are logged in.',
                data: null,
                errorCode: 'AUTH_REQUIRED'
            });
        }

        // Validate quiz mode
        var quizModeType = request.quizModeType;
        if (quizModeType === undefined || quizModeType === null) {
            return JSON.stringify({ success: false, message: 'Quiz mode type is required', data: null });
        }

        var quizModeName = request.quizModeName || 'Quiz Challenge';
        var quizConfig = request.quizConfig || null;
        var sessionId = nk.uuidv4();
        var shareCode = asyncChallengeGenerateShareCode(sessionId);
        var now = Date.now();
        var expiresAt = now + (48 * 60 * 60 * 1000); // 48h default

        // Fetch creator display name
        var displayName = request.playerDisplayName || 'Player';
        try {
            var users = nk.usersGetId([userId]);
            if (users && users.length > 0) {
                displayName = users[0].displayName || users[0].username || displayName;
            }
        } catch (userErr) {
            logger.warn('[AsyncChallenge] Could not fetch user info: ' + userErr.message);
        }

        // Check for max active challenges (prevent spam — max 10)
        try {
            var existing = nk.storageList(userId, COLLECTION_ASYNC_CHALLENGES, 20, '');
            var activeCount = 0;
            var existingObjs = existing.objects || [];
            for (var i = 0; i < existingObjs.length; i++) {
                var obj = existingObjs[i];
                if (obj.key.indexOf('code_') === 0) continue;
                var s = obj.value;
                var st = typeof s.status === 'number' ? s.status : 0;
                if (st < 2 && now < s.expiresAt) activeCount++;
            }
            if (activeCount >= 10) {
                return JSON.stringify({
                    success: false,
                    message: 'Maximum active challenges reached (10). Please complete or cancel existing ones.',
                    data: null,
                    errorCode: 'MAX_CHALLENGES'
                });
            }
        } catch (listErr) {
            logger.warn('[AsyncChallenge] Could not check active challenges: ' + listErr.message);
        }

        var gameId = '';
        try {
            var account = nk.accountGetId(userId);
            if (account && account.user && account.user.metadata) {
                var meta = account.user.metadata;
                gameId = meta.gameId || meta.game_id || '';
            }
        } catch (accErr) {
            // Fallback — no gameId
        }

        // Internal storage
        var sessionStorage = {
            sessionId: sessionId,
            shareCode: shareCode,
            quizModeType: quizModeType,
            quizModeName: quizModeName,
            quizConfig: quizConfig,
            gameId: gameId,
            creatorId: userId,
            creatorName: displayName,
            opponentId: request.challengedUserId || null,
            opponentName: request.challengedDisplayName || null,
            status: 0, // WaitingForOpponent
            createdAt: now,
            expiresAt: expiresAt,
            creatorResult: null,
            opponentResult: null,
            finalResult: null
        };

        // Write session under creator's account
        nk.storageWrite([{
            collection: COLLECTION_ASYNC_CHALLENGES,
            key: sessionId,
            userId: userId,
            value: sessionStorage,
            permissionRead: 2,
            permissionWrite: 1
        }]);

        // Write public code mapping under system user
        nk.storageWrite([{
            collection: COLLECTION_ASYNC_CHALLENGES,
            key: 'code_' + shareCode,
            userId: '00000000-0000-0000-0000-000000000000',
            value: { sessionId: sessionId, creatorId: userId, quizModeType: quizModeType },
            permissionRead: 2,
            permissionWrite: 0
        }]);

        logger.info('[AsyncChallenge] Session created: ' + sessionId + ' code: ' + shareCode + ' mode: ' + quizModeName);

        // If challenging a specific friend, send them a notification
        if (request.challengedUserId) {
            asyncChallengeSendNotification(nk, logger, request.challengedUserId,
                'Quiz Challenge!',
                displayName + ' challenged you to ' + quizModeName + '!',
                {
                    notificationType: 'challenge_received',
                    sessionId: sessionId,
                    shareCode: shareCode,
                    quizModeType: quizModeType,
                    quizModeName: quizModeName,
                    challengerName: displayName,
                    challengerId: userId
                }
            );
        }

        // Format and enrich with avatar URLs
        var formattedChallenge = asyncChallengeToUnityFormat(sessionStorage);
        formattedChallenge = enrichSingleSessionWithAvatars(nk, logger, formattedChallenge);
        
        return JSON.stringify({
            success: true,
            message: 'Challenge created successfully',
            data: formattedChallenge
        });
    } catch (err) {
        logger.error('[AsyncChallenge] Create error: ' + err.message);
        return JSON.stringify({ success: false, message: err.message, data: null });
    }
}

/**
 * RPC: Join an existing async challenge
 * Payload: { shareCode: string, playerDisplayName?: string, userId?: string }
 */
function rpcAsyncChallengeJoin(ctx, logger, nk, payload) {
    logger.debug('[AsyncChallenge] User ' + ctx.userId + ' attempting to join challenge');

    var request;
    try {
        request = JSON.parse(payload || '{}');
    } catch (e) {
        return JSON.stringify({ success: false, message: 'Invalid JSON payload', data: null });
    }

    try {
        // Auth validation
        var userId = ctx.userId;
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            userId = request.userId;
        }
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            return JSON.stringify({
                success: false, message: 'User authentication required.',
                data: null, errorCode: 'AUTH_REQUIRED'
            });
        }

        var shareCode = (request.shareCode || '').toUpperCase().trim();
        if (!shareCode || shareCode.length < 4) {
            return JSON.stringify({ success: false, message: 'Invalid share code', data: null });
        }

        // Lookup code mapping
        var codeResults = nk.storageRead([{
            collection: COLLECTION_ASYNC_CHALLENGES,
            key: 'code_' + shareCode,
            userId: '00000000-0000-0000-0000-000000000000'
        }]);

        if (codeResults.length === 0) {
            return JSON.stringify({ success: false, message: 'Challenge not found. Please check the code and try again.', data: null });
        }

        var codeRecord = codeResults[0].value;
        var sessionId = codeRecord.sessionId;
        var creatorId = codeRecord.creatorId;

        // Read session
        var sessionResults = nk.storageRead([{
            collection: COLLECTION_ASYNC_CHALLENGES,
            key: sessionId,
            userId: creatorId
        }]);

        if (sessionResults.length === 0) {
            return JSON.stringify({ success: false, message: 'Challenge data not found', data: null });
        }

        var session = sessionResults[0].value;
        var now = Date.now();

        // Validation checks
        if (session.status === 3 || session.status === 4 || now > session.expiresAt) {
            var reason = session.status === 4 ? 'This challenge was cancelled.' : 'This challenge has expired.';
            return JSON.stringify({ success: false, message: reason, data: null });
        }

        if (session.creatorId === userId) {
            return JSON.stringify({ success: false, message: 'You cannot join your own challenge', data: null });
        }

        // If already has an opponent and it's someone else
        if (session.opponentId && session.opponentId !== userId) {
            return JSON.stringify({ success: false, message: 'This challenge already has an opponent', data: null });
        }

        // If directed challenge and user doesn't match
        if (session.opponentId && session.opponentId !== userId) {
            return JSON.stringify({ success: false, message: 'This challenge was sent to a different player', data: null });
        }

        // Fetch joiner's display name
        var displayName = request.playerDisplayName || 'Player';
        try {
            var users = nk.usersGetId([userId]);
            if (users && users.length > 0) {
                displayName = users[0].displayName || users[0].username || displayName;
            }
        } catch (userErr) {
            logger.warn('[AsyncChallenge] Could not fetch user info: ' + userErr.message);
        }

        // Update session
        session.opponentId = userId;
        session.opponentName = displayName;
        if (session.status === 0) {
            session.status = 1; // OpponentJoined
        }

        nk.storageWrite([{
            collection: COLLECTION_ASYNC_CHALLENGES,
            key: sessionId,
            userId: creatorId,
            value: session,
            permissionRead: 2,
            permissionWrite: 1
        }]);

        // Notify creator
        asyncChallengeSendNotification(nk, logger, session.creatorId,
            'Challenge Accepted!',
            displayName + ' accepted your ' + session.quizModeName + ' challenge!',
            {
                notificationType: 'challenge_accepted',
                sessionId: sessionId,
                opponentName: displayName,
                opponentId: userId,
                quizModeType: session.quizModeType,
                quizModeName: session.quizModeName
            }
        );

        logger.info('[AsyncChallenge] User ' + userId + ' joined challenge ' + sessionId);

        // Format and enrich with avatar URLs
        var formattedSession = asyncChallengeToUnityFormat(session);
        formattedSession = enrichSingleSessionWithAvatars(nk, logger, formattedSession);

        return JSON.stringify({
            success: true,
            message: 'Successfully joined challenge',
            data: formattedSession
        });
    } catch (err) {
        logger.error('[AsyncChallenge] Join error: ' + err.message);
        return JSON.stringify({ success: false, message: err.message, data: null });
    }
}

/**
 * RPC: Get challenge details
 * Payload: { sessionId?: string, shareCode?: string, userId?: string }
 */
function rpcAsyncChallengeGet(ctx, logger, nk, payload) {
    var request;
    try {
        request = JSON.parse(payload || '{}');
    } catch (e) {
        return JSON.stringify({ success: false, message: 'Invalid JSON payload', data: null });
    }

    try {
        var userId = ctx.userId;
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            userId = request.userId;
        }
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            return JSON.stringify({
                success: false, message: 'User authentication required.',
                data: null, errorCode: 'AUTH_REQUIRED'
            });
        }

        var sessionId = request.sessionId;
        var creatorId = null;

        // Resolve from share code if needed
        if (!sessionId && request.shareCode) {
            var shareCode = request.shareCode.toUpperCase().trim();
            var codeResults = nk.storageRead([{
                collection: COLLECTION_ASYNC_CHALLENGES,
                key: 'code_' + shareCode,
                userId: '00000000-0000-0000-0000-000000000000'
            }]);
            if (codeResults.length === 0) {
                return JSON.stringify({ success: false, message: 'Challenge not found', data: null });
            }
            sessionId = codeResults[0].value.sessionId;
            creatorId = codeResults[0].value.creatorId;
        }

        if (!sessionId) {
            return JSON.stringify({ success: false, message: 'Session ID or share code required', data: null });
        }

        // Try reading as the requesting user first (they might be creator)
        var sessionResults = nk.storageRead([{
            collection: COLLECTION_ASYNC_CHALLENGES,
            key: sessionId,
            userId: userId
        }]);

        // Fallback: read using creatorId from code mapping
        if (sessionResults.length === 0 && creatorId) {
            sessionResults = nk.storageRead([{
                collection: COLLECTION_ASYNC_CHALLENGES,
                key: sessionId,
                userId: creatorId
            }]);
        }

        // Fallback: search all storage
        if (sessionResults.length === 0) {
            var listResults = nk.storageList(null, COLLECTION_ASYNC_CHALLENGES, 100, '');
            var objects = listResults.objects || [];
            for (var i = 0; i < objects.length; i++) {
                if (objects[i].value.sessionId === sessionId) {
                    creatorId = objects[i].value.creatorId;
                    break;
                }
            }
            if (creatorId) {
                sessionResults = nk.storageRead([{
                    collection: COLLECTION_ASYNC_CHALLENGES,
                    key: sessionId,
                    userId: creatorId
                }]);
            }
        }

        if (sessionResults.length === 0) {
            return JSON.stringify({ success: false, message: 'Challenge not found', data: null });
        }

        var session = sessionResults[0].value;

        // Authorization check
        if (session.creatorId !== userId && session.opponentId !== userId) {
            return JSON.stringify({ success: false, message: 'Not authorized to view this challenge', data: null });
        }

        // Format and enrich with avatar URLs
        var formattedSession = asyncChallengeToUnityFormat(session);
        formattedSession = enrichSingleSessionWithAvatars(nk, logger, formattedSession);

        return JSON.stringify({
            success: true,
            message: 'Challenge retrieved',
            data: formattedSession
        });
    } catch (err) {
        logger.error('[AsyncChallenge] Get error: ' + err.message);
        return JSON.stringify({ success: false, message: err.message, data: null });
    }
}

/**
 * RPC: Submit quiz results for an async challenge
 * Payload: {
 *   sessionId: string,
 *   score: number,
 *   correctAnswers: number,
 *   totalQuestions: number,
 *   timeTaken: number,
 *   accuracy?: number,
 *   userId?: string
 * }
 */
function rpcAsyncChallengeSubmit(ctx, logger, nk, payload) {
    logger.debug('[AsyncChallenge] User ' + ctx.userId + ' submitting results');

    var request;
    try {
        request = JSON.parse(payload || '{}');
    } catch (e) {
        return JSON.stringify({ success: false, message: 'Invalid JSON payload', data: null });
    }

    try {
        var userId = ctx.userId;
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            userId = request.userId;
        }
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            return JSON.stringify({
                success: false, message: 'User authentication required.',
                data: null, errorCode: 'AUTH_REQUIRED'
            });
        }

        var sessionId = request.sessionId;
        if (!sessionId) {
            return JSON.stringify({ success: false, message: 'Session ID required', data: null });
        }

        // Validate score data
        var score = typeof request.score === 'number' ? request.score : 0;
        var correctAnswers = typeof request.correctAnswers === 'number' ? request.correctAnswers : 0;
        var totalQuestions = typeof request.totalQuestions === 'number' ? request.totalQuestions : 0;
        var timeTaken = typeof request.timeTaken === 'number' ? request.timeTaken : 0;

        // Bounds validation
        if (score < 0) score = 0;
        if (score > 999999) score = 999999;
        if (correctAnswers < 0) correctAnswers = 0;
        if (totalQuestions < 0) totalQuestions = 0;
        if (correctAnswers > totalQuestions && totalQuestions > 0) correctAnswers = totalQuestions;
        if (timeTaken < 0) timeTaken = 0;

        // Find session - try as creator first
        var sessionResults = nk.storageRead([{
            collection: COLLECTION_ASYNC_CHALLENGES,
            key: sessionId,
            userId: userId
        }]);

        var isCreator = sessionResults.length > 0;
        var creatorId = isCreator ? userId : null;

        // If not creator, search for it
        if (!isCreator) {
            var listResults = nk.storageList(null, COLLECTION_ASYNC_CHALLENGES, 100, '');
            var objects = listResults.objects || [];
            for (var i = 0; i < objects.length; i++) {
                var obj = objects[i];
                if (obj.value.sessionId === sessionId &&
                    (obj.value.opponentId === userId || obj.value.creatorId === userId)) {
                    creatorId = obj.value.creatorId;
                    isCreator = obj.value.creatorId === userId;
                    break;
                }
            }

            if (creatorId) {
                sessionResults = nk.storageRead([{
                    collection: COLLECTION_ASYNC_CHALLENGES,
                    key: sessionId,
                    userId: creatorId
                }]);
            }
        }

        if (sessionResults.length === 0) {
            return JSON.stringify({ success: false, message: 'Challenge not found', data: null });
        }

        var session = sessionResults[0].value;
        var now = Date.now();

        // Validate session state
        if (session.status === 3 || now > session.expiresAt) {
            return JSON.stringify({ success: false, message: 'Challenge has expired', data: null });
        }
        if (session.status === 4) {
            return JSON.stringify({ success: false, message: 'Challenge was cancelled', data: null });
        }

        isCreator = session.creatorId === userId;
        var isOpponent = session.opponentId === userId;

        if (!isCreator && !isOpponent) {
            return JSON.stringify({ success: false, message: 'Not authorized for this challenge', data: null });
        }

        // Prevent double submission
        if (isCreator && session.creatorResult && session.creatorResult.isComplete) {
            return JSON.stringify({ success: false, message: 'You have already submitted your results', data: null, errorCode: 'ALREADY_SUBMITTED' });
        }
        if (isOpponent && session.opponentResult && session.opponentResult.isComplete) {
            return JSON.stringify({ success: false, message: 'You have already submitted your results', data: null, errorCode: 'ALREADY_SUBMITTED' });
        }

        var accuracy = totalQuestions > 0 ? Math.round((correctAnswers / totalQuestions) * 1000) / 10 : 0;
        if (typeof request.accuracy === 'number') accuracy = request.accuracy;

        var resultData = {
            score: score,
            correctAnswers: correctAnswers,
            totalQuestions: totalQuestions,
            timeTaken: timeTaken,
            accuracy: accuracy,
            isComplete: true,
            completedAt: now
        };

        if (isCreator) {
            session.creatorResult = resultData;
        } else {
            session.opponentResult = resultData;
        }

        // Update status
        var creatorDone = session.creatorResult && session.creatorResult.isComplete;
        var opponentDone = session.opponentResult && session.opponentResult.isComplete;

        if (creatorDone && opponentDone) {
            session.status = 2; // BothCompleted
            // Compute final result
            session.finalResult = asyncChallengeComputeResult(session);
        } else {
            // At least one has submitted, keep at joined status
            if (session.status < 1) session.status = 1;
        }

        // Persist
        nk.storageWrite([{
            collection: COLLECTION_ASYNC_CHALLENGES,
            key: sessionId,
            userId: session.creatorId,
            value: session,
            permissionRead: 2,
            permissionWrite: 1
        }]);

        // Send notifications
        if (isCreator && session.opponentId) {
            asyncChallengeSendNotification(nk, logger, session.opponentId,
                'Opponent Finished!',
                session.creatorName + ' completed the ' + session.quizModeName + ' challenge with ' + score + ' points!',
                {
                    notificationType: 'opponent_completed',
                    sessionId: sessionId,
                    quizModeType: session.quizModeType,
                    quizModeName: session.quizModeName,
                    opponentScore: score
                }
            );
        } else if (isOpponent) {
            asyncChallengeSendNotification(nk, logger, session.creatorId,
                'Challenge Complete!',
                session.opponentName + ' completed the ' + session.quizModeName + ' challenge with ' + score + ' points!',
                {
                    notificationType: 'opponent_completed',
                    sessionId: sessionId,
                    quizModeType: session.quizModeType,
                    quizModeName: session.quizModeName,
                    opponentScore: score
                }
            );
        }

        // If both completed, send results notification to both
        if (session.status === 2 && session.finalResult) {
            var resultMsg = session.finalResult.isDraw
                ? "It's a draw! Both scored " + session.finalResult.creatorScore + " points!"
                : session.finalResult.winnerName + ' won by ' + session.finalResult.scoreDifference + ' points!';

            asyncChallengeSendNotification(nk, logger, session.creatorId,
                'Challenge Results!',
                resultMsg,
                {
                    notificationType: 'results_ready',
                    sessionId: sessionId,
                    quizModeName: session.quizModeName,
                    winnerId: session.finalResult.winnerId,
                    isDraw: session.finalResult.isDraw
                }
            );

            if (session.opponentId) {
                asyncChallengeSendNotification(nk, logger, session.opponentId,
                    'Challenge Results!',
                    resultMsg,
                    {
                        notificationType: 'results_ready',
                        sessionId: sessionId,
                        quizModeName: session.quizModeName,
                        winnerId: session.finalResult.winnerId,
                        isDraw: session.finalResult.isDraw
                    }
                );
            }
        }

        logger.info('[AsyncChallenge] Results submitted for session ' + sessionId + ' by ' + (isCreator ? 'creator' : 'opponent'));

        // Format and enrich with avatar URLs
        var formattedResult = asyncChallengeToUnityFormat(session);
        formattedResult = enrichSingleSessionWithAvatars(nk, logger, formattedResult);

        return JSON.stringify({
            success: true,
            message: session.status === 2 ? 'Results submitted! Challenge complete!' : 'Results submitted successfully',
            data: formattedResult
        });
    } catch (err) {
        logger.error('[AsyncChallenge] Submit error: ' + err.message);
        return JSON.stringify({ success: false, message: err.message, data: null });
    }
}

/**
 * RPC: List user's async challenges
 * Payload: { limit?: number, includeExpired?: boolean, status?: number, userId?: string }
 */
function rpcAsyncChallengeList(ctx, logger, nk, payload) {
    var request = {};
    try {
        if (payload) request = JSON.parse(payload);
    } catch (e) { /* defaults */ }

    try {
        var userId = ctx.userId;
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            userId = request.userId;
        }
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            return JSON.stringify({
                success: false, message: 'User authentication required.',
                data: [], errorCode: 'AUTH_REQUIRED'
            });
        }

        var limit = Math.min(request.limit || 20, 100);
        var includeExpired = request.includeExpired || false;
        var filterStatus = request.status !== undefined ? request.status : null;
        var now = Date.now();

        // Sessions where user is creator
        var creatorSessions = nk.storageList(userId, COLLECTION_ASYNC_CHALLENGES, limit, '');
        var sessions = [];
        var objects = creatorSessions.objects || [];

        for (var i = 0; i < objects.length; i++) {
            var obj = objects[i];
            if (obj.key.indexOf('code_') === 0) continue;

            var session = obj.value;
            var status = typeof session.status === 'number' ? session.status : 0;
            var isExpired = status === 3 || now > session.expiresAt;

            if (!includeExpired && isExpired && status < 2) continue;
            if (filterStatus !== null && status !== filterStatus) continue;

            sessions.push(asyncChallengeToUnityFormat(session));
        }

        // Also find sessions where user is opponent (search system-wide)
        try {
            var systemSessions = nk.storageList(null, COLLECTION_ASYNC_CHALLENGES, 200, '');
            var sysObjects = systemSessions.objects || [];
            var seenIds = {};
            for (var s = 0; s < sessions.length; s++) {
                seenIds[sessions[s].sessionId] = true;
            }

            for (var j = 0; j < sysObjects.length; j++) {
                var sObj = sysObjects[j];
                if (sObj.key.indexOf('code_') === 0) continue;
                var sSession = sObj.value;

                if (sSession.opponentId === userId && !seenIds[sSession.sessionId]) {
                    var sStatus = typeof sSession.status === 'number' ? sSession.status : 0;
                    var sIsExpired = sStatus === 3 || now > sSession.expiresAt;

                    if (!includeExpired && sIsExpired && sStatus < 2) continue;
                    if (filterStatus !== null && sStatus !== filterStatus) continue;

                    sessions.push(asyncChallengeToUnityFormat(sSession));
                    seenIds[sSession.sessionId] = true;
                }
            }
        } catch (searchErr) {
            logger.warn('[AsyncChallenge] Could not search opponent sessions: ' + searchErr.message);
        }

        // Sort by createdAt descending
        sessions.sort(function(a, b) { return (b.createdAt || 0) - (a.createdAt || 0); });

        // Limit results
        if (sessions.length > limit) {
            sessions = sessions.slice(0, limit);
        }

        // Enrich sessions with avatar URLs
        sessions = enrichSessionsWithAvatars(nk, logger, sessions);

        return JSON.stringify({
            success: true,
            message: 'Challenges retrieved',
            data: sessions,
            total: sessions.length
        });
    } catch (err) {
        logger.error('[AsyncChallenge] List error: ' + err.message);
        return JSON.stringify({ success: false, message: err.message, data: [] });
    }
}

/**
 * RPC: Cancel an async challenge (creator only)
 * Payload: { sessionId: string, userId?: string }
 */
function rpcAsyncChallengeCancel(ctx, logger, nk, payload) {
    var request;
    try {
        request = JSON.parse(payload || '{}');
    } catch (e) {
        return JSON.stringify({ success: false, message: 'Invalid JSON payload', data: null });
    }

    try {
        var userId = ctx.userId;
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            userId = request.userId;
        }
        if (!userId || typeof userId !== 'string' || userId.length < 10) {
            return JSON.stringify({
                success: false, message: 'User authentication required.',
                data: null, errorCode: 'AUTH_REQUIRED'
            });
        }

        var sessionId = request.sessionId;
        if (!sessionId) {
            return JSON.stringify({ success: false, message: 'Session ID required', data: null });
        }

        var sessionResults = nk.storageRead([{
            collection: COLLECTION_ASYNC_CHALLENGES,
            key: sessionId,
            userId: userId
        }]);

        if (sessionResults.length === 0) {
            return JSON.stringify({ success: false, message: 'Challenge not found or not authorized', data: null });
        }

        var session = sessionResults[0].value;

        if (session.creatorId !== userId) {
            return JSON.stringify({ success: false, message: 'Only the challenge creator can cancel', data: null });
        }

        if (session.status === 2) {
            return JSON.stringify({ success: false, message: 'Cannot cancel a completed challenge', data: null });
        }

        session.status = 4; // Cancelled

        nk.storageWrite([{
            collection: COLLECTION_ASYNC_CHALLENGES,
            key: sessionId,
            userId: userId,
            value: session,
            permissionRead: 2,
            permissionWrite: 1
        }]);

        // Notify opponent if one exists
        if (session.opponentId) {
            asyncChallengeSendNotification(nk, logger, session.opponentId,
                'Challenge Cancelled',
                session.creatorName + ' cancelled the ' + session.quizModeName + ' challenge.',
                {
                    notificationType: 'challenge_cancelled',
                    sessionId: sessionId,
                    quizModeName: session.quizModeName
                }
            );
        }

        logger.info('[AsyncChallenge] Session ' + sessionId + ' cancelled by creator');

        // Format and enrich with avatar URLs
        var cancelledSession = asyncChallengeToUnityFormat(session);
        cancelledSession = enrichSingleSessionWithAvatars(nk, logger, cancelledSession);

        return JSON.stringify({
            success: true,
            message: 'Challenge cancelled',
            data: cancelledSession
        });
    } catch (err) {
        logger.error('[AsyncChallenge] Cancel error: ' + err.message);
        return JSON.stringify({ success: false, message: err.message, data: null });
    }
}

